Refactor the following code: greybus: es2: drop redundant device reference.

Refactor strategy: add error pointer handling

Refactoring description:
Driver core holds a reference to the USB interface and its parent USB
device while the interface is bound to a driver and there is no need to
take additional references unless the structures are needed after
disconnect.

Drop the redundant device reference to reduce cargo culting, make it
easier to spot drivers where an extra reference is needed, and reduce
the risk of memory leaks when drivers fail to release it.

Output the complete corrected function(s).

```c
/*
* The ES2 USB Bridge device has 15 endpoints
* 1 Control - usual USB stuff + AP -> APBridgeA messages
* 7 Bulk IN - CPort data in
* 7 Bulk OUT - CPort data out
*/
static int ap_probe(struct usb_interface *interface,
		   const struct usb_device_id *id)
{
       struct es2_ap_dev *es2;
       struct gb_host_device *hd;
       struct usb_device *udev;
       struct usb_host_interface *iface_desc;
       struct usb_endpoint_descriptor *endpoint;
       __u8 ep_addr;
       int retval;
       int i;
       int num_cports;
       bool bulk_out_found = false;
       bool bulk_in_found = false;
       bool arpc_in_found = false;

       udev = usb_get_dev(interface_to_usbdev(interface));

       num_cports = apb_get_cport_count(udev);
       if (num_cports < 0) {
	       usb_put_dev(udev);
	       dev_err(&udev->dev, "Cannot retrieve CPort count: %d\n",
		       num_cports);
	       return num_cports;
       }

       hd = gb_hd_create(&es2_driver, &udev->dev, ES2_GBUF_MSG_SIZE_MAX,
			 num_cports);
       if (IS_ERR(hd)) {
	       usb_put_dev(udev);
	       return PTR_ERR(hd);
       }

       es2 = hd_to_es2(hd);
       es2->hd = hd;
       es2->usb_intf = interface;
       es2->usb_dev = udev;
       spin_lock_init(&es2->cport_out_urb_lock);
       INIT_KFIFO(es2->apb_log_fifo);
       usb_set_intfdata(interface, es2);

       /*
	* Reserve the CDSI0 and CDSI1 CPorts so they won't be allocated
	* dynamically.
