Fix the following bug in the code below: netfilter: flowtable: ensure sufficient headroom in xmit path.

Problem description:
Check for headroom and call skb_expand_head() like in the IP output
path to ensure there is sufficient headroom for the mac header when
forwarding this packet as suggested by sashiko.

Output the complete corrected function(s).

```c
static unsigned int nf_flow_queue_xmit(struct net *net, struct sk_buff *skb,
			       struct nf_flow_xmit *xmit)
{
skb->dev = xmit->outdev;
dev_hard_header(skb, skb->dev, ntohs(skb->protocol),
		xmit->dest, xmit->source, skb->len);
dev_queue_xmit(skb);

return NF_STOLEN;
}
```

```c
static unsigned int nf_flow_queue_xmit(struct net *net, struct sk_buff *skb,
			       struct nf_flow_xmit *xmit)
{
struct net_device *dev = xmit->outdev;
unsigned int hh_len = LL_RESERVED_SPACE(dev);

if (unlikely(skb_headroom(skb) < hh_len && dev->header_ops)) {
	skb = skb_expand_head(skb, hh_len);
	if (!skb)
		return NF_STOLEN;
}

skb->dev = dev;
dev_hard_header(skb, dev, ntohs(skb->protocol),
		xmit->dest, xmit->source, skb->len);
dev_queue_xmit(skb);

return NF_STOLEN;
}
```

Implement the following feature in the code below: selftests/bpf: add test for xdp_master_redirect with bond not up.

Feature description:
Add a selftest that reproduces the null-ptr-deref in
bond_rr_gen_slave_id() when XDP redirect targets a bond device in
round-robin mode that was never brought up. The test verifies the fix
by ensuring no crash occurs.

Test setup:
- bond0: active-backup mode, UP, with native XDP (enables
  bpf_master_redirect_enabled_key globally)
- bond1: round-robin mode, never UP
- veth1: slave of bond1, with generic XDP (XDP_TX)
- BPF_PROG_TEST_RUN with live frames triggers the redirect path

Output the complete corrected function(s).

```c
void serial_test_xdp_bonding(void)
{
libbpf_print_fn_t old_print_fn;
struct skeletons skeletons = {};
int i;

old_print_fn = libbpf_set_print(libbpf_debug_print);

root_netns_fd = open("/proc/self/ns/net", O_RDONLY);
if (!ASSERT_GE(root_netns_fd, 0, "open /proc/self/ns/net"))
	goto out;

skeletons.xdp_dummy = xdp_dummy__open_and_load();
if (!ASSERT_OK_PTR(skeletons.xdp_dummy, "xdp_dummy__open_and_load"))
	goto out;

skeletons.xdp_tx = xdp_tx__open_and_load();
if (!ASSERT_OK_PTR(skeletons.xdp_tx, "xdp_tx__open_and_load"))
	goto out;

skeletons.xdp_redirect_multi_kern = xdp_redirect_multi_kern__open_and_load();
if (!ASSERT_OK_PTR(skeletons.xdp_redirect_multi_kern,
		   "xdp_redirect_multi_kern__open_and_load"))
	goto out;

if (test__start_subtest("xdp_bonding_attach"))
	test_xdp_bonding_attach(&skeletons);

if (test__start_subtest("xdp_bonding_nested"))
	test_xdp_bonding_nested(&skeletons);

if (test__start_subtest("xdp_bonding_features"))
	test_xdp_bonding_features(&skeletons);

for (i = 0; i < ARRAY_SIZE(bond_test_cases); i++) {
	struct bond_test_case *test_case = &bond_test_cases[i];

	if (test__start_subtest(test_case->name))
		test_xdp_bonding_with_mode(
			&skeletons,
			test_case->mode,
			test_case->xmit_policy);
}

if (test__start_subtest("xdp_bonding_xmit_policy_compat"))
	test_xdp_bonding_xmit_policy_compat(&skeletons);

if (test__start_subtest("xdp_bonding_redirect_multi"))
	test_xdp_bonding_redirect_multi(&skeletons);

out:
xdp_dummy__destroy(skeletons.xdp_dummy);
xdp_tx__destroy(skeletons.xdp_tx);
xdp_redirect_multi_kern__destroy(skeletons.xdp_redirect_multi_kern);

libbpf_set_print(old_print_fn);
if (root_netns_fd >= 0)
	close(root_netns_fd);
}
