Implement the following feature in the code below: perf trace: Skip unnecessary synthesis for summary-only mode.

Feature description:
It needs to synthesize task info for the comm name.  The mmap
information is only needed for callchain symbolization which is not used
by the summary mode.  Also total or cgroup summary mode don't require
the task info.  Let's skip the processing if possible.

Output the complete corrected function(s).

```c
static int trace__symbols_init(struct trace *trace, int argc, const char **argv,
		       struct evlist *evlist)
{
int err = symbol__init(NULL);

if (err)
	return err;

perf_env__init(&trace->host_env);
err = perf_env__set_cmdline(&trace->host_env, argc, argv);
if (err)
	goto out;

trace->host = machine__new_host(&trace->host_env);
if (trace->host == NULL) {
	err = -ENOMEM;
	goto out;
}
thread__set_priv_destructor(thread_trace__delete);

err = trace_event__register_resolver(trace->host, trace__machine__resolve_kernel_addr);
if (err < 0)
	goto out;

err = __machine__synthesize_threads(trace->host, &trace->tool, &trace->opts.target,
				    evlist->core.threads, trace__tool_process,
				    /*needs_mmap=*/callchain_param.enabled,
				    /*mmap_data=*/false,
				    /*nr_threads_synthesize=*/1);
out:
if (err) {
	perf_env__exit(&trace->host_env);
	symbol__exit();
}
return err;
}
