protocol = usblp_select_alts(usblp);
if (protocol < 0) {
	dev_dbg(&intf->dev,
		"incompatible printer-class device 0x%4.4X/0x%4.4X\n",
		le16_to_cpu(dev->descriptor.idVendor),
		le16_to_cpu(dev->descriptor.idProduct));
	retval = -ENODEV;
	goto abort;
}

