	le16_to_cpu(usblp->dev->descriptor.idProduct));

return 0;

abort_intfdata:
usb_set_intfdata(intf, NULL);
abort:
kfree(usblp->readbuf);
kfree(usblp->statusbuf);
kfree(usblp->device_id_string);
usb_put_intf(usblp->intf);
kfree(usblp)
