Implement the following feature in the code below: ASoC: nau8325: Add software reset during probe.

Feature description:
Currently, the driver only performs a hardware reset during the I2C probe
sequence. To ensure all internal states of the codec are properly cleared
without affecting the configuration registers, a software reset is also
required.

According to the hardware specification, writing to the Software Reset
register (R01) twice will reset all internal states safely.

This patch adds the nau8325_software_reset() function, executes it right
after the hardware reset in the probe function, and marks the R01 register
as writeable in the regmap configuration.

Output the complete corrected function(s).

```c
static int nau8325_i2c_probe(struct i2c_client *i2c)
{
struct device *dev = &i2c->dev;
struct nau8325 *nau8325 = dev_get_platdata(dev);
int ret, value;

if (!nau8325) {
	nau8325 = devm_kzalloc(dev, sizeof(*nau8325), GFP_KERNEL);
	if (!nau8325) {
		ret = -ENOMEM;
		goto err;
	}
	ret = nau8325_read_device_properties(dev, nau8325);
	if (ret)
		goto err;
}
i2c_set_clientdata(i2c, nau8325);

nau8325->regmap = devm_regmap_init_i2c(i2c, &nau8325_regmap_config);
if (IS_ERR(nau8325->regmap)) {
	ret = PTR_ERR(nau8325->regmap);
	goto err;
}
nau8325->dev = dev;
nau8325_print_device_properties(nau8325);

nau8325_reset_chip(nau8325->regmap);
ret = regmap_read(nau8325->regmap, NAU8325_R02_DEVICE_ID, &value);
if (ret) {
	dev_dbg(dev, "Failed to read device id (%d)", ret);
	goto err;
}
nau8325_init_regs(nau8325);

ret = devm_snd_soc_register_component(dev, &nau8325_component_driver,
				      &nau8325_dai, 1);
err:
return ret;
}
