Fix the following bug in the code below: comedi: me4000: Fix potential overrun of firmware buffer.

Fix strategy: add error return

Problem description:
`me4000_xilinx_download()` loads the firmware that was requested by
`request_firmware()`.  It is possible for it to overrun the source
buffer because it blindly trusts the file format.  It reads a data
stream length from the first 4 bytes into variable `file_length` and
reads the data stream contents of length `file_length` from offset 16
onwards.

Add a test to ensure that the supplied firmware is long enough to
contain the header and the data stream.  On failure, log an error and
return `-EINVAL`.

Note: The firmware loading was totally broken before commit ac584af59945
("staging: comedi: me4000: fix firmware downloading"), but that is the
most sensible target for this fix.

Output the complete corrected function(s).

```c
static int me4000_xilinx_download(struct comedi_device *dev,
			  const u8 *data, size_t size,
			  unsigned long context)
{
struct pci_dev *pcidev = comedi_to_pci_dev(dev);
struct me4000_private *devpriv = dev->private;
unsigned long xilinx_iobase = pci_resource_start(pcidev, 5);
unsigned int file_length;
unsigned int val;
unsigned int i;

if (!xilinx_iobase)
	return -ENODEV;

/*
 * Set PLX local interrupt 2 polarity to high.
 * Interrupt is thrown by init pin of xilinx.
 */
outl(PLX9052_INTCSR_LI2POL, devpriv->plx_regbase + PLX9052_INTCSR);

/* Set /CS and /WRITE of the Xilinx */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
val |= PLX9052_CNTRL_UIO2_DATA;
outl(val, devpriv->plx_regbase + PLX9052_CNTRL);

/* Init Xilinx with CS1 */
inb(xilinx_iobase + 0xC8);

/* Wait until /INIT pin is set */
usleep_range(20, 1000);
val = inl(devpriv->plx_regbase + PLX9052_INTCSR);
if (!(val & PLX9052_INTCSR_LI2STAT)) {
	dev_err(dev->class_dev, "Can't init Xilinx\n");
	return -EIO;
}

/* Reset /CS and /WRITE of the Xilinx */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
val &= ~PLX9052_CNTRL_UIO2_DATA;
outl(val, devpriv->plx_regbase + PLX9052_CNTRL);

/* Download Xilinx firmware */
file_length = (((unsigned int)data[0] & 0xff) << 24) +
	      (((unsigned int)data[1] & 0xff) << 16) +
	      (((unsigned int)data[2] & 0xff) << 8) +
	      ((unsigned int)data[3] & 0xff);
usleep_range(10, 1000);

for (i = 0; i < file_length; i++) {
	outb(data[16 + i], xilinx_iobase);
	usleep_range(10, 1000);

	/* Check if BUSY flag is low */
	val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
	if (val & PLX9052_CNTRL_UIO1_DATA) {
		dev_err(dev->class_dev,
			"Xilinx is still busy (i = %d)\n", i);
		return -EIO;
	}
}

/* If done flag is high download was successful */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
if (!(val & PLX9052_CNTRL_UIO0_DATA)) {
	dev_err(dev->class_dev, "DONE flag is not set\n");
	dev_err(dev->class_dev, "Download not successful\n");
	return -EIO;
}

/* Set /CS and /WRITE */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
val |= PLX9052_CNTRL_UIO2_DATA;
outl(val, devpriv->plx_regbase + PLX9052_CNTRL);

return 0;
}
```

```c
static int me4000_xilinx_download(struct comedi_device *dev,
			  const u8 *data, size_t size,
			  unsigned long context)
{
struct pci_dev *pcidev = comedi_to_pci_dev(dev);
struct me4000_private *devpriv = dev->private;
unsigned long xilinx_iobase = pci_resource_start(pcidev, 5);
unsigned int file_length;
unsigned int val;
unsigned int i;

/* Get data stream length from header. */
if (size >= 4) {
	file_length = (((unsigned int)data[0] & 0xff) << 24) +
		      (((unsigned int)data[1] & 0xff) << 16) +
		      (((unsigned int)data[2] & 0xff) << 8) +
		      ((unsigned int)data[3] & 0xff);
}
if (size < 16 || file_length > size - 16) {
	dev_err(dev->class_dev, "Firmware length inconsistency\n");
	return -EINVAL;
}

if (!xilinx_iobase)
	return -ENODEV;

/*
 * Set PLX local interrupt 2 polarity to high.
 * Interrupt is thrown by init pin of xilinx.
 */
outl(PLX9052_INTCSR_LI2POL, devpriv->plx_regbase + PLX9052_INTCSR);

/* Set /CS and /WRITE of the Xilinx */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
val |= PLX9052_CNTRL_UIO2_DATA;
outl(val, devpriv->plx_regbase + PLX9052_CNTRL);

/* Init Xilinx with CS1 */
inb(xilinx_iobase + 0xC8);

/* Wait until /INIT pin is set */
usleep_range(20, 1000);
val = inl(devpriv->plx_regbase + PLX9052_INTCSR);
if (!(val & PLX9052_INTCSR_LI2STAT)) {
	dev_err(dev->class_dev, "Can't init Xilinx\n");
	return -EIO;
}

/* Reset /CS and /WRITE of the Xilinx */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
val &= ~PLX9052_CNTRL_UIO2_DATA;
outl(val, devpriv->plx_regbase + PLX9052_CNTRL);

/* Download Xilinx firmware */
usleep_range(10, 1000);

for (i = 0; i < file_length; i++) {
	outb(data[16 + i], xilinx_iobase);
	usleep_range(10, 1000);

	/* Check if BUSY flag is low */
	val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
	if (val & PLX9052_CNTRL_UIO1_DATA) {
		dev_err(dev->class_dev,
			"Xilinx is still busy (i = %d)\n", i);
		return -EIO;
	}
}

/* If done flag is high download was successful */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
if (!(val & PLX9052_CNTRL_UIO0_DATA)) {
	dev_err(dev->class_dev, "DONE flag is not set\n");
	dev_err(dev->class_dev, "Download not successful\n");
	return -EIO;
}

/* Set /CS and /WRITE */
val = inl(devpriv->plx_regbase + PLX9052_CNTRL);
val |= PLX9052_CNTRL_UIO2_DATA;
outl(val, devpriv->plx_regbase + PLX9052_CNTRL);

return 0;
}
