Implement the following feature in the code below: tracing/fprobe: Remove fprobe from hash in failure path.

Feature description:
When register_fprobe_ips() fails, it tries to remove a list of
fprobe_hash_node from fprobe_ip_table, but it missed to remove
fprobe itself from fprobe_table. Moreover, when removing
the fprobe_hash_node which is added to rhltable once, it must
use kfree_rcu() after removing from rhltable.

To fix these issues, this reuses unregister_fprobe() internal
code to rollback the half-way registered fprobe.

Output the complete corrected function(s).

```c
/* Initialize the fprobe data structure. */
static int fprobe_init(struct fprobe *fp, unsigned long *addrs, int num)
{
struct fprobe_hlist *hlist_array;
unsigned long addr;
int size, i;

if (!fp || !addrs || num <= 0)
	return -EINVAL;

size = ALIGN(fp->entry_data_size, sizeof(long));
if (size > MAX_FPROBE_DATA_SIZE)
	return -E2BIG;
fp->entry_data_size = size;

hlist_array = kzalloc_flex(*hlist_array, array, num);
if (!hlist_array)
	return -ENOMEM;

fp->nmissed = 0;

hlist_array->size = num;
fp->hlist_array = hlist_array;
hlist_array->fp = fp;
for (i = 0; i < num; i++) {
	hlist_array->array[i].fp = fp;
	addr = ftrace_location(addrs[i]);
	if (!addr) {
		fprobe_fail_cleanup(fp);
		return -ENOENT;
	}
	hlist_array->array[i].addr = addr;
}
return 0;
}
```

