	WRITE_ONCE(desc->msg1, 0);
	WRITE_ONCE(desc->msg2, 0);
	WRITE_ONCE(desc->msg3, 0);

	q->tail = (q->tail + 1) % q->ndesc;
	q->queued--;
}

q->head = q->tail;
airoha_qdma_rmw(qdma, REG_RX_DMA_IDX(qid), RX_RING_DMA_IDX_MASK,
		FIELD_PREP(RX_RING_DMA_IDX_MASK, q->tail));
