static void f81604_write_bulk_callback(struct urb *urb)
{
struct net_device *netdev = urb->context;

if (!netif_device_present(netdev))
	return;

if (!urb->status)
	return;

switch (urb->status) {
case -ENOENT:
case -ECONNRESET:
case -ESHUTDOWN:
	return;
default:
	break;
}

if (net_ratelimit())
