Implement the following feature in the code below: bpf: Switch CONFIG_CFI_CLANG to CONFIG_CFI.

Feature description:
This was renamed in commit 23ef9d439769 ("kcfi: Rename CONFIG_CFI_CLANG
to CONFIG_CFI") as it is now a compiler-agnostic option. Using the wrong
name results in the code getting compiled out. Meaning the CFI failures
for btf_dtor_kfunc_t would still trigger.

Output the complete corrected function(s).

```c
static int btf_check_dtor_kfuncs(struct btf *btf, const struct btf_id_dtor_kfunc *dtors, u32 cnt)
{
const struct btf_type *dtor_func, *dtor_func_proto, *t;
const struct btf_param *args;
s32 dtor_btf_id;
u32 nr_args, i;

for (i = 0; i < cnt; i++) {
	dtor_btf_id = btf_relocate_id(btf, dtors[i].kfunc_btf_id);

	dtor_func = btf_type_by_id(btf, dtor_btf_id);
	if (!dtor_func || !btf_type_is_func(dtor_func))
		return -EINVAL;

	dtor_func_proto = btf_type_by_id(btf, dtor_func->type);
	if (!dtor_func_proto || !btf_type_is_func_proto(dtor_func_proto))
		return -EINVAL;

	/* Make sure the prototype of the destructor kfunc is 'void func(type *)' */
	t = btf_type_by_id(btf, dtor_func_proto->type);
	if (!t || !btf_type_is_void(t))
		return -EINVAL;

	nr_args = btf_type_vlen(dtor_func_proto);
	if (nr_args != 1)
		return -EINVAL;
	args = btf_params(dtor_func_proto);
	t = btf_type_by_id(btf, args[0].type);
	/* Allow any pointer type, as width on targets Linux supports
	 * will be same for all pointer types (i.e. sizeof(void *))
	 */
	if (!t || !btf_type_is_ptr(t))
		return -EINVAL;

	if (IS_ENABLED(CONFIG_CFI_CLANG)) {
		/* Ensure the destructor kfunc type matches btf_dtor_kfunc_t */
		t = btf_type_by_id(btf, t->type);
		if (!btf_type_is_void(t))
			return -EINVAL;
	}
}
return 0;
}
