Refactor the following code: iommu/vt-d: Remove the remaining pages along the invalidation path.

Refactoring description:
This was only being used to signal that a flush all should be used.
Use mask/size_order >= 52 to signal this instead.

Output the complete corrected function(s).

```c
/*
* Invalidates a range of IOVA from @start (inclusive) to @end (inclusive)
* when the memory mappings in the target domain have been modified.
*/
void cache_tag_flush_range(struct dmar_domain *domain, unsigned long start,
			  unsigned long end, int ih)
{
       struct intel_iommu *iommu = NULL;
       unsigned long pages, mask, addr;
       struct cache_tag *tag;
       unsigned long flags;

       if (start == 0 && end == ULONG_MAX) {
	       addr = 0;
	       pages = -1;
	       mask = MAX_AGAW_PFN_WIDTH;
       } else {
	       addr = calculate_psi_aligned_address(start, end, &pages, &mask);
       }

       spin_lock_irqsave(&domain->cache_lock, flags);
       list_for_each_entry(tag, &domain->cache_tags, node) {
	       if (iommu && iommu != tag->iommu)
		       qi_batch_flush_descs(iommu, domain->qi_batch);
	       iommu = tag->iommu;

	       switch (tag->type) {
	       case CACHE_TAG_IOTLB:
	       case CACHE_TAG_NESTING_IOTLB:
		       cache_tag_flush_iotlb(domain, tag, addr, pages, mask, ih);
		       break;
	       case CACHE_TAG_NESTING_DEVTLB:
		       /*
			* Address translation cache in device side caches the
			* result of nested translation. There is no easy way
			* to identify the exact set of nested translations
			* affected by a change in S2. So just flush the entire
			* device cache.
			*/
		       addr = 0;
		       mask = MAX_AGAW_PFN_WIDTH;
		       fallthrough;
	       case CACHE_TAG_DEVTLB:
		       cache_tag_flush_devtlb_psi(domain, tag, addr, mask);
		       break;
	       }

	       trace_cache_tag_flush_range(tag, start, end, addr, pages, mask);
       }
       qi_batch_flush_descs(iommu, domain->qi_batch);
       spin_unlock_irqrestore(&domain->cache_lock, flags);
}
