Fix the following bug in the code below: i3c: master: dw-i3c: Fix missing reset assertion in remove() callback.

Problem description:
The reset line acquired during probe is currently left deasserted when
the driver is unbound.

Switch to devm_reset_control_get_optional_exclusive_deasserted() to
ensure the reset is automatically re-asserted by the devres core when
the driver is removed.

Output the complete corrected function(s).

```c
int dw_i3c_common_probe(struct dw_i3c_master *master,
		struct platform_device *pdev)
{
int ret, irq;
const struct dw_i3c_drvdata *drvdata;
unsigned long quirks = 0;

if (!master->platform_ops)
	master->platform_ops = &dw_i3c_platform_ops_default;

master->dev = &pdev->dev;

master->regs = devm_platform_ioremap_resource(pdev, 0);
if (IS_ERR(master->regs))
	return PTR_ERR(master->regs);

master->core_clk = devm_clk_get_enabled(&pdev->dev, NULL);
if (IS_ERR(master->core_clk))
	return PTR_ERR(master->core_clk);

master->pclk = devm_clk_get_optional_enabled(&pdev->dev, "pclk");
if (IS_ERR(master->pclk))
	return PTR_ERR(master->pclk);

master->core_rst = devm_reset_control_get_optional_exclusive(&pdev->dev,
							    "core_rst");
if (IS_ERR(master->core_rst))
	return PTR_ERR(master->core_rst);

reset_control_deassert(master->core_rst);

spin_lock_init(&master->xferqueue.lock);
INIT_LIST_HEAD(&master->xferqueue.list);

spin_lock_init(&master->devs_lock);

writel(INTR_ALL, master->regs + INTR_STATUS);
irq = platform_get_irq(pdev, 0);
ret = devm_request_irq(&pdev->dev, irq,
		       dw_i3c_master_irq_handler, 0,
		       dev_name(&pdev->dev), master);
if (ret)
	goto err_assert_rst;

platform_set_drvdata(pdev, master);

pm_runtime_set_autosuspend_delay(&pdev->dev, RPM_AUTOSUSPEND_TIMEOUT);
pm_runtime_use_autosuspend(&pdev->dev);
pm_runtime_set_active(&pdev->dev);
pm_runtime_enable(&pdev->dev);

/* Information regarding the FIFOs/QUEUEs depth */
ret = readl(master->regs + QUEUE_STATUS_LEVEL);
master->caps.cmdfifodepth = QUEUE_STATUS_LEVEL_CMD(ret);

ret = readl(master->regs + DATA_BUFFER_STATUS_LEVEL);
master->caps.datafifodepth = DATA_BUFFER_STATUS_LEVEL_TX(ret);

ret = readl(master->regs + DEVICE_ADDR_TABLE_POINTER);
master->datstartaddr = ret;
master->maxdevs = ret >> 16;
master->free_pos = GENMASK(master->maxdevs - 1, 0);

if (has_acpi_companion(&pdev->dev)) {
	quirks = (unsigned long)device_get_match_data(&pdev->dev);
} else if (pdev->dev.of_node) {
	drvdata = device_get_match_data(&pdev->dev);
	if (drvdata)
		quirks = drvdata->flags;
}
master->quirks = quirks;

/* Keep controller enabled by preventing runtime suspend */
if (master->quirks & DW_I3C_DISABLE_RUNTIME_PM_QUIRK)
	pm_runtime_get_noresume(&pdev->dev);

INIT_WORK(&master->hj_work, dw_i3c_hj_work);

device_set_of_node_from_dev(&master->base.i2c.dev, &pdev->dev);
ret = i3c_master_register(&master->base, &pdev->dev,
			  &dw_mipi_i3c_ops, false);
if (ret)
	goto err_disable_pm;

return 0;

err_disable_pm:
pm_runtime_disable(&pdev->dev);
pm_runtime_set_suspended(&pdev->dev);
pm_runtime_dont_use_autosuspend(&pdev->dev);

err_assert_rst:
reset_control_assert(master->core_rst);

return ret;
}
