Refactor the following code: wifi: ipw2x00: replace use of system_wq with system_percpu_wq.

Refactoring description:
This patch continues the effort to refactor workqueue APIs, which has begun
with the changes introducing new workqueues and a new alloc_workqueue flag:

   commit 128ea9f6ccfb ("workqueue: Add system_percpu_wq and system_dfl_wq")
   commit 930c2ea566af ("workqueue: Add new WQ_PERCPU flag")

The point of the refactoring is to eventually alter the default behavior of
workqueues to become unbound by default so that their workload placement is
optimized by the scheduler.

Before that to happen after a careful review and conversion of each individual
case, workqueue users must be converted to the better named new workqueues with
no intended behaviour changes:

   system_wq -> system_percpu_wq
   system_unbound_wq -> systemd_dfl_wq

This way the old obsolete workqueues (system_wq, system_unbound_wq) can be
removed in the future.

Output the complete corrected function(s).

```c
/* File: drivers/net/wireless/intel/ipw2x00/ipw2100.c */
static void isr_indicate_rf_kill(struct ipw2100_priv *priv, u32 status)
{
IPW_DEBUG_INFO("%s: RF Kill state changed to radio OFF.\n",
	       priv->net_dev->name);

/* RF_KILL is now enabled (else we wouldn't be here) */
wiphy_rfkill_set_hw_state(priv->ieee->wdev.wiphy, true);
priv->status |= STATUS_RF_KILL_HW;

/* Make sure the RF Kill check timer is running */
priv->stop_rf_kill = 0;
mod_delayed_work(system_wq, &priv->rf_kill, round_jiffies_relative(HZ));
}

/* --- separate code section --- */

/* File: drivers/net/wireless/intel/ipw2x00/ipw2100.c */
static void isr_scan_complete(struct ipw2100_priv *priv, u32 status)
{
IPW_DEBUG_SCAN("scan complete\n");
/* Age the scan results... */
priv->ieee->scans++;
priv->status &= ~STATUS_SCANNING;

/* Only userspace-requested scan completion events go out immediately */
if (!priv->user_requested_scan) {
	schedule_delayed_work(&priv->scan_event,
			      round_jiffies_relative(msecs_to_jiffies(4000)));
} else {
	priv->user_requested_scan = 0;
	mod_delayed_work(system_wq, &priv->scan_event, 0);
}
}

/* --- separate code section --- */

/* File: drivers/net/wireless/intel/ipw2x00/ipw2100.c */
static int ipw_radio_kill_sw(struct ipw2100_priv *priv, int disable_radio)
{
if ((disable_radio ? 1 : 0) ==
    (priv->status & STATUS_RF_KILL_SW ? 1 : 0))
	return 0;

IPW_DEBUG_RF_KILL("Manual SW RF Kill set to: RADIO  %s\n",
		  disable_radio ? "OFF" : "ON");

mutex_lock(&priv->action_mutex);

if (disable_radio) {
	priv->status |= STATUS_RF_KILL_SW;
	ipw2100_down(priv);
} else {
	priv->status &= ~STATUS_RF_KILL_SW;
	if (rf_kill_active(priv)) {
		IPW_DEBUG_RF_KILL("Can not turn radio back on - "
				  "disabled by HW switch\n");
		/* Make sure the RF_KILL check timer is running */
		priv->stop_rf_kill = 0;
		mod_delayed_work(system_wq, &priv->rf_kill,
				 round_jiffies_relative(HZ));
	} else
		schedule_reset(priv);
}

mutex_unlock(&priv->action_mutex);
return 1;
}
