Fix the following bug in the code below: irqchip/gic-v3: Print a warning for out-of-range interrupt numbers.

Problem description:
gic_irq_domain_translate() does not check if an interrupt number lies
within the valid range of the specified interrupt type.  Add these checks,
and print a warning if the interrupt number is out of range.

This can help flagging incorrectly described Extended SPI and PPI
interrupts in DT.

Output the complete corrected function(s).

```c
static int gic_irq_domain_translate(struct irq_domain *d,
			    struct irq_fwspec *fwspec,
			    unsigned long *hwirq,
			    unsigned int *type)
{
if (fwspec->param_count == 1 && fwspec->param[0] < 16) {
	*hwirq = fwspec->param[0];
	*type = IRQ_TYPE_EDGE_RISING;
	return 0;
}

if (is_of_node(fwspec->fwnode)) {
	if (fwspec->param_count < 3)
		return -EINVAL;

	switch (fwspec->param[0]) {
	case 0:			/* SPI */
		*hwirq = fwspec->param[1] + 32;
		break;
	case 1:			/* PPI */
		*hwirq = fwspec->param[1] + 16;
		break;
	case 2:			/* ESPI */
		*hwirq = fwspec->param[1] + ESPI_BASE_INTID;
		break;
	case 3:			/* EPPI */
		*hwirq = fwspec->param[1] + EPPI_BASE_INTID;
		break;
	case GIC_IRQ_TYPE_LPI:	/* LPI */
		*hwirq = fwspec->param[1];
		break;
	default:
		return -EINVAL;
	}

	*type = fwspec->param[2] & IRQ_TYPE_SENSE_MASK;

	/*
	 * Make it clear that broken DTs are... broken.
	 */
	WARN_ON(*type == IRQ_TYPE_NONE);
	return 0;
}

if (is_fwnode_irqchip(fwspec->fwnode)) {
	if(fwspec->param_count != 2)
		return -EINVAL;

	if (fwspec->param[0] < 16) {
		pr_err(FW_BUG "Illegal GSI%d translation request\n",
		       fwspec->param[0]);
		return -EINVAL;
	}

	*hwirq = fwspec->param[0];
	*type = fwspec->param[1];

	WARN_ON(*type == IRQ_TYPE_NONE);
	return 0;
}

return -EINVAL;
}
```

