	if (found_start > start) {
		if (slot == 0) {
			ret = btrfs_previous_item(stripe_root, path, 0,
						  BTRFS_RAID_STRIPE_KEY);
			if (ret) {
				if (ret > 0)
					ret = -ENOENT;
				break;
			}
