Fix the following bug in the code below: kho: fix KASAN support for restored vmalloc regions.

Problem description:
Restored vmalloc regions are currently not properly marked for KASAN,
causing KASAN to treat accesses to these regions as out-of-bounds.

Fix this by properly unpoisoning the restored vmalloc area using
kasan_unpoison_vmalloc().  This requires setting the VM_UNINITIALIZED flag
during the initial area allocation and clearing it after the pages have
been mapped and unpoisoned, using the clear_vm_uninitialized_flag()
helper.

Output the complete corrected function(s).

```c
/**
* kho_restore_vmalloc - recreates and populates an area in vmalloc address
* space from the preserved memory.
* @preservation: preservation metadata.
*
* Recreates an area in vmalloc address space and populates it with memory that
* was preserved using kho_preserve_vmalloc().
*
* Return: pointer to the area in the vmalloc address space, NULL on failure.
*/
void *kho_restore_vmalloc(const struct kho_vmalloc *preservation)
{
       struct kho_vmalloc_chunk *chunk = KHOSER_LOAD_PTR(preservation->first);
       unsigned int align, order, shift, vm_flags;
       unsigned long total_pages, contig_pages;
       unsigned long addr, size;
       struct vm_struct *area;
       struct page **pages;
       unsigned int idx = 0;
       int err;

       vm_flags = kho_flags_to_vmalloc(preservation->flags);
       if (vm_flags & ~KHO_VMALLOC_SUPPORTED_FLAGS)
	       return NULL;

       total_pages = preservation->total_pages;
       pages = kvmalloc_objs(*pages, total_pages);
       if (!pages)
	       return NULL;
       order = preservation->order;
       contig_pages = (1 << order);
       shift = PAGE_SHIFT + order;
       align = 1 << shift;

       while (chunk) {
	       struct page *page;

	       for (int i = 0; i < ARRAY_SIZE(chunk->phys) && chunk->phys[i]; i++) {
		       phys_addr_t phys = chunk->phys[i];

		       if (idx + contig_pages > total_pages)
			       goto err_free_pages_array;

		       page = kho_restore_pages(phys, contig_pages);
		       if (!page)
			       goto err_free_pages_array;

		       for (int j = 0; j < contig_pages; j++)
			       pages[idx++] = page + j;

		       phys += contig_pages * PAGE_SIZE;
	       }

	       page = kho_restore_pages(virt_to_phys(chunk), 1);
	       if (!page)
		       goto err_free_pages_array;
	       chunk = KHOSER_LOAD_PTR(chunk->hdr.next);
	       __free_page(page);
       }

       if (idx != total_pages)
	       goto err_free_pages_array;

       area = __get_vm_area_node(total_pages * PAGE_SIZE, align, shift,
				 vm_flags, VMALLOC_START, VMALLOC_END,
				 NUMA_NO_NODE, GFP_KERNEL,
				 __builtin_return_address(0));
       if (!area)
	       goto err_free_pages_array;

       addr = (unsigned long)area->addr;
       size = get_vm_area_size(area);
       err = vmap_pages_range(addr, addr + size, PAGE_KERNEL, pages, shift);
       if (err)
	       goto err_free_vm_area;

       area->nr_pages = total_pages;
       area->pages = pages;

       return area->addr;

err_free_vm_area:
       free_vm_area(area);
err_free_pages_array:
       kvfree(pages);
       return NULL;
}
```

