Fix the following bug in the code below: jbd2: gracefully abort on checkpointing state corruptions.

Fix strategy: add unlock; add error return

Problem description:
This patch targets two internal state machine invariants in checkpoint.c
residing inside functions that natively return integer error codes.

- In jbd2_cleanup_journal_tail(): A blocknr of 0 indicates a severely
corrupted journal superblock. Replaced the J_ASSERT with a WARN_ON_ONCE
and a graceful journal abort, returning -EFSCORRUPTED.

- In jbd2_log_do_checkpoint(): Replaced the J_ASSERT_BH checking for
an unexpected buffer_jwrite state. If the warning triggers, we
explicitly drop the just-taken get_bh() reference and call __flush_batch()
to safely clean up any previously queued buffers in the j_chkpt_bhs array,
preventing a memory leak before returning -EFSCORRUPTED.

Output the complete corrected function(s).

```c
/*
* Perform an actual checkpoint. We take the first transaction on the
* list of transactions to be checkpointed and send all its buffers
* to disk. We submit larger chunks of data at once.
*
* The journal should be locked before calling this function.
* Called with j_checkpoint_mutex held.
*/
int jbd2_log_do_checkpoint(journal_t *journal)
{
       struct journal_head	*jh;
       struct buffer_head	*bh;
       transaction_t		*transaction;
       tid_t			this_tid;
       int			result, batch_count = 0;

       jbd2_debug(1, "Start checkpoint\n");

       /*
	* First thing: if there are any transactions in the log which
	* don't need checkpointing, just eliminate them from the
	* journal straight away.
	*/
       result = jbd2_cleanup_journal_tail(journal);
       trace_jbd2_checkpoint(journal, result);
       jbd2_debug(1, "cleanup_journal_tail returned %d\n", result);
       if (result <= 0)
	       return result;

       /*
	* OK, we need to start writing disk blocks.  Take one transaction
	* and write it.
	*/
       spin_lock(&journal->j_list_lock);
       if (!journal->j_checkpoint_transactions)
	       goto out;
       transaction = journal->j_checkpoint_transactions;
       if (transaction->t_chp_stats.cs_chp_time == 0)
	       transaction->t_chp_stats.cs_chp_time = jiffies;
       this_tid = transaction->t_tid;
restart:
       /*
	* If someone cleaned up this transaction while we slept, we're
	* done (maybe it's a new transaction, but it fell at the same
	* address).
	*/
       if (journal->j_checkpoint_transactions != transaction ||
	   transaction->t_tid != this_tid)
	       goto out;

       /* checkpoint all of the transaction's buffers */
       while (transaction->t_checkpoint_list) {
	       jh = transaction->t_checkpoint_list;
	       bh = jh2bh(jh);

	       if (jh->b_transaction != NULL) {
		       transaction_t *t = jh->b_transaction;
		       tid_t tid = t->t_tid;

		       transaction->t_chp_stats.cs_forced_to_close++;
		       spin_unlock(&journal->j_list_lock);
		       if (unlikely(journal->j_flags & JBD2_UNMOUNT))
			       /*
				* The journal thread is dead; so
				* starting and waiting for a commit
				* to finish will cause us to wait for
				* a _very_ long time.
				*/
			       printk(KERN_ERR
	       "JBD2: %s: Waiting for Godot: block %llu\n",
	       journal->j_devname, (unsigned long long) bh->b_blocknr);

		       if (batch_count)
			       __flush_batch(journal, &batch_count);
		       jbd2_log_start_commit(journal, tid);
		       /*
			* jbd2_journal_commit_transaction() may want
			* to take the checkpoint_mutex if JBD2_FLUSHED
			* is set, jbd2_update_log_tail() called by
			* jbd2_journal_commit_transaction() may also take
			* checkpoint_mutex.  So we need to temporarily
			* drop it.
			*/
		       mutex_unlock(&journal->j_checkpoint_mutex);
		       jbd2_log_wait_commit(journal, tid);
		       mutex_lock_io(&journal->j_checkpoint_mutex);
		       spin_lock(&journal->j_list_lock);
		       goto restart;

