Refactor the following code: spi: spi-fsl-lpspi: fsl_lpspi_write_tx_fifo(): simplify while() loop check.

Refactoring description:
To simplify the loop check. Combine both conditions of the while() and the
directly following if() into the while().

Output the complete corrected function(s).

```c
/* File: drivers/spi/spi-fsl-lpspi.c */
static void fsl_lpspi_write_tx_fifo(struct fsl_lpspi_data *fsl_lpspi)
{
u8 txfifo_cnt;
u32 temp;

txfifo_cnt = readl(fsl_lpspi->base + IMX7ULP_FSR) & 0xff;

while (txfifo_cnt < fsl_lpspi->txfifosize) {
	if (!fsl_lpspi->remain)
		break;
	fsl_lpspi->tx(fsl_lpspi);
	txfifo_cnt++;
}

if (txfifo_cnt < fsl_lpspi->txfifosize) {
	if (!fsl_lpspi->is_target) {
		temp = readl(fsl_lpspi->base + IMX7ULP_TCR);
		temp &= ~TCR_CONTC;
		writel(temp, fsl_lpspi->base + IMX7ULP_TCR);
	}

	fsl_lpspi_intctrl(fsl_lpspi, IER_FCIE);
} else {
	fsl_lpspi_intctrl(fsl_lpspi, IER_TDIE);
}
}
