/* File: fs/btrfs/extent_io.c */
int btree_writepages(struct address_space *mapping, struct writeback_control *wbc)
{
struct btrfs_eb_write_context ctx = { .wbc = wbc };
struct btrfs_fs_info *fs_info = inode_to_fs_info(mapping->host);
int ret = 0;
int done = 0;
int nr_to_write_done = 0;
struct eb_batch batch;
unsigned int nr_ebs;
unsigned long index;
unsigned long end;
int scanned = 0;
xa_mark_t tag;

eb_batch_init(&batch);
if (wbc->range_cyclic) {
	index = ((mapping->writeback_index << PAGE_SHIFT) >> fs_info->nodesize_bits);
	end = -1;

	/*
	 * Start from the beginning does not need to cycle over the
	 * range, mark it as scanned.
	 */
	scanned = (index == 0);
} else {
	index = (wbc->range_start >> fs_info->nodesize_bits);
	end = (wbc->range_end >> fs_info->nodesize_bits);

	scanned = 1;
}
if (wbc->sync_mode == WB_SYNC_ALL)
	tag = PAGECACHE_TAG_TOWRITE;
else
	tag = PAGECACHE_TAG_DIRTY;
btrfs_zoned_meta_io_lock(fs_info);
retry:
if (wbc->sync_mode == WB_SYNC_ALL)
	buffer_tree_tag_for_writeback(fs_info, index, end);
while (!done && !nr_to_write_done && (index <= end) &&
       (nr_ebs = buffer_tree_get_ebs_tag(fs_info, &index, end, tag, &batch))) {
	struct extent_buffer *eb;

	while ((eb = eb_batch_next(&batch)) != NULL) {
		ctx.eb = eb;

		ret = btrfs_check_meta_write_pointer(eb->fs_info, &ctx);
		if (ret) {
			if (ret == -EBUSY)
				ret = 0;

			if (ret) {
				done = 1;
				break;
			}
			continue;
		}

		if (!lock_extent_buffer_for_io(eb, wbc))
			continue;

		/* Implies write in zoned mode. */
		if (ctx.zoned_bg) {
			/* Mark the last eb in the block group. */
			btrfs_schedule_zone_finish_bg(ctx.zoned_bg, eb);
			ctx.zoned_bg->meta_write_pointer += eb->len;
		}
		write_one_eb(eb, wbc);
	}
	nr_to_write_done = (wbc->nr_to_write <= 0);
	eb_batch_release(&batch);
	cond_resched();
}
if (!scanned && !done) {
	/*
	 * We hit the last page and there is more work to be done: wrap
	 * back to the start of the file
	 */
	scanned = 1;
	index = 0;
	goto retry;
}

/*
 * Only btrfs_check_meta_write_pointer() can update @ret,
 * and it only returns 0 or errors.
 */
ASSERT(ret <= 0);
if (!ret && BTRFS_FS_ERROR(fs_info))
	ret = -EROFS;

if (ctx.zoned_bg)
	btrfs_put_block_group(ctx.zoned_bg);
btrfs_zoned_meta_io_unlock(fs_info);
return ret;
}
