       if (XE_IOCTL_DBG(xe, args->flags & ~DRM_XE_EXEC_QUEUE_LOW_LATENCY_HINT) ||
	   XE_IOCTL_DBG(xe, args->reserved[0] || args->reserved[1]))
	       return -EINVAL;

