Implement the following feature in the code below: riscv: Reset pmm when PR_TAGGED_ADDR_ENABLE is not set.

Feature description:
In set_tagged_addr_ctrl(), when PR_TAGGED_ADDR_ENABLE is not set, pmlen
is correctly set to 0, but it forgets to reset pmm. This results in the
CPU pmm state not corresponding to the software pmlen state.

Fix this by resetting pmm along with pmlen.

Output the complete corrected function(s).

```c
long set_tagged_addr_ctrl(struct task_struct *task, unsigned long arg)
{
unsigned long valid_mask = PR_PMLEN_MASK | PR_TAGGED_ADDR_ENABLE;
struct thread_info *ti = task_thread_info(task);
struct mm_struct *mm = task->mm;
unsigned long pmm;
u8 pmlen;

if (!riscv_has_extension_unlikely(RISCV_ISA_EXT_SUPM))
	return -EINVAL;

if (is_compat_thread(ti))
	return -EINVAL;

if (arg & ~valid_mask)
	return -EINVAL;

/*
 * Prefer the smallest PMLEN that satisfies the user's request,
 * in case choosing a larger PMLEN has a performance impact.
 */
pmlen = FIELD_GET(PR_PMLEN_MASK, arg);
if (pmlen == PMLEN_0) {
	pmm = ENVCFG_PMM_PMLEN_0;
} else if (pmlen <= PMLEN_7 && have_user_pmlen_7) {
	pmlen = PMLEN_7;
	pmm = ENVCFG_PMM_PMLEN_7;
} else if (pmlen <= PMLEN_16 && have_user_pmlen_16) {
	pmlen = PMLEN_16;
	pmm = ENVCFG_PMM_PMLEN_16;
} else {
	return -EINVAL;
}

/*
 * Do not allow the enabling of the tagged address ABI if globally
 * disabled via sysctl abi.tagged_addr_disabled, if pointer masking
 * is disabled for userspace.
 */
if (arg & PR_TAGGED_ADDR_ENABLE && (tagged_addr_disabled || !pmlen))
	return -EINVAL;

if (!(arg & PR_TAGGED_ADDR_ENABLE))
	pmlen = PMLEN_0;

if (mmap_write_lock_killable(mm))
	return -EINTR;

if (test_bit(MM_CONTEXT_LOCK_PMLEN, &mm->context.flags) && mm->context.pmlen != pmlen) {
	mmap_write_unlock(mm);
	return -EBUSY;
}

envcfg_update_bits(task, ENVCFG_PMM, pmm);
mm->context.pmlen = pmlen;

mmap_write_unlock(mm);

return 0;
}
```

