Implement the following feature in the code below: netfilter: nft_fwd_netdev: add device and headroom validate with neigh forwarding.

Feature description:
The ttl field has been decremented already and evaluation of this rule
would proceed, just drop this packet instead if there is no destination
device to forwards this packet. This is exactly what nf_dup already does
in this case.

Moreover, check for headroom and call skb_expand_head() like in the IP
output path to ensure there is sufficient headroom when forwarding this
via neigh_xmit().

Output the complete corrected function(s).

```c
static void nft_fwd_neigh_eval(const struct nft_expr *expr,
		      struct nft_regs *regs,
		      const struct nft_pktinfo *pkt)
{
struct nft_fwd_neigh *priv = nft_expr_priv(expr);
void *addr = &regs->data[priv->sreg_addr];
int oif = regs->data[priv->sreg_dev];
unsigned int verdict = NF_STOLEN;
struct sk_buff *skb = pkt->skb;
int nhoff = skb_network_offset(skb);
struct net_device *dev;
int neigh_table;

switch (priv->nfproto) {
case NFPROTO_IPV4: {
	struct iphdr *iph;

	if (skb->protocol != htons(ETH_P_IP)) {
		verdict = NFT_BREAK;
		goto out;
	}
	if (skb_ensure_writable(skb, nhoff + sizeof(*iph))) {
		verdict = NF_DROP;
		goto out;
	}
	iph = ip_hdr(skb);
	if (iph->ttl <= 1) {
		verdict = NF_DROP;
		goto out;
	}

	ip_decrease_ttl(iph);
	neigh_table = NEIGH_ARP_TABLE;
	break;
	}
case NFPROTO_IPV6: {
	struct ipv6hdr *ip6h;

	if (skb->protocol != htons(ETH_P_IPV6)) {
		verdict = NFT_BREAK;
		goto out;
	}
	if (skb_ensure_writable(skb, nhoff + sizeof(*ip6h))) {
		verdict = NF_DROP;
		goto out;
	}
	ip6h = ipv6_hdr(skb);
	if (ip6h->hop_limit <= 1) {
		verdict = NF_DROP;
		goto out;
	}

	ip6h->hop_limit--;
	neigh_table = NEIGH_ND_TABLE;
	break;
	}
default:
	verdict = NFT_BREAK;
	goto out;
}

dev = dev_get_by_index_rcu(nft_net(pkt), oif);
if (dev == NULL)
	return;

skb->dev = dev;
skb_clear_tstamp(skb);
neigh_xmit(neigh_table, dev, addr, skb);
out:
regs->verdict.code = verdict;
}
```

