Implement the following feature in the code below: gpio: sim: stop using dev-sync-probe.

Feature description:
dev-err-probe is an overengineered solution to a simple problem. Use a
combination of wait_for_probe() and device_is_bound() to synchronously
wait for the platform device to probe.

Output the complete corrected function(s).

```c
static int gpio_sim_device_activate(struct gpio_sim_device *dev)
{
struct platform_device_info pdevinfo;
struct fwnode_handle *swnode;
struct gpio_sim_bank *bank;
int ret;

lockdep_assert_held(&dev->lock);

if (list_empty(&dev->bank_list))
	return -ENODATA;

/*
 * Non-unique GPIO device labels are a corner-case we don't support
 * as it would interfere with machine hogging mechanism and has little
 * use in real life.
 */
if (gpio_sim_bank_labels_non_unique(dev))
	return -EINVAL;

memset(&pdevinfo, 0, sizeof(pdevinfo));

swnode = fwnode_create_software_node(NULL, NULL);
if (IS_ERR(swnode))
	return PTR_ERR(swnode);

list_for_each_entry(bank, &dev->bank_list, siblings) {
	bank->swnode = gpio_sim_make_bank_swnode(bank, swnode);
	if (IS_ERR(bank->swnode)) {
		ret = PTR_ERR(bank->swnode);
		gpio_sim_remove_swnode_recursive(swnode);
		return ret;
	}

	ret = gpio_sim_bank_add_hogs(bank);
	if (ret) {
		gpio_sim_remove_swnode_recursive(swnode);
		return ret;
	}
}

pdevinfo.name = "gpio-sim";
pdevinfo.fwnode = swnode;
pdevinfo.id = dev->id;

ret = dev_sync_probe_register(&dev->probe_data, &pdevinfo);
if (ret) {
	gpio_sim_remove_swnode_recursive(swnode);
	return ret;
}

return 0;
}
```

```c
static int gpio_sim_device_activate(struct gpio_sim_device *dev)
{
struct platform_device_info pdevinfo;
struct platform_device *pdev;
struct fwnode_handle *swnode;
struct gpio_sim_bank *bank;
int ret;

lockdep_assert_held(&dev->lock);

if (list_empty(&dev->bank_list))
	return -ENODATA;

/*
 * Non-unique GPIO device labels are a corner-case we don't support
 * as it would interfere with machine hogging mechanism and has little
 * use in real life.
 */
if (gpio_sim_bank_labels_non_unique(dev))
	return -EINVAL;

memset(&pdevinfo, 0, sizeof(pdevinfo));

swnode = fwnode_create_software_node(NULL, NULL);
if (IS_ERR(swnode))
	return PTR_ERR(swnode);

list_for_each_entry(bank, &dev->bank_list, siblings) {
	bank->swnode = gpio_sim_make_bank_swnode(bank, swnode);
	if (IS_ERR(bank->swnode)) {
		ret = PTR_ERR(bank->swnode);
		goto err_remove_swnode;
	}

	ret = gpio_sim_bank_add_hogs(bank);
	if (ret)
		goto err_remove_swnode;
}

pdevinfo.name = "gpio-sim";
pdevinfo.fwnode = swnode;
pdevinfo.id = dev->id;

pdev = platform_device_register_full(&pdevinfo);
if (IS_ERR(pdev)) {
	ret = PTR_ERR(pdev);
	goto err_remove_swnode;
}

wait_for_device_probe();
if (!device_is_bound(&pdev->dev)) {
	ret = -ENXIO;
	goto err_unregister_pdev;
}

dev->pdev = pdev;
return 0;

err_unregister_pdev:
platform_device_unregister(pdev);
err_remove_swnode:
gpio_sim_remove_swnode_recursive(swnode);

return ret;
}
