Implement the following feature in the code below: kho: fix kho_in_debugfs_init() to handle non-FDT blobs.

Feature description:
kho_in_debugfs_init() calls fdt_totalsize() to determine blob sizes, which
assumes all blobs are FDTs.  This breaks for non-FDT blobs like struct
kho_kexec_metadata.

Fix this by reading the "blob-size" property from the FDT (persisted by
kho_add_subtree()) instead of calling fdt_totalsize().  Also rename local
variables from fdt_phys/sub_fdt to blob_phys/blob for consistency with the
non-FDT-specific naming.

Output the complete corrected function(s).

```c
__init void kho_in_debugfs_init(struct kho_debugfs *dbg, const void *fdt)
{
struct dentry *dir, *sub_fdt_dir;
int err, child;

INIT_LIST_HEAD(&dbg->fdt_list);

dir = debugfs_create_dir("in", debugfs_root);
if (IS_ERR(dir)) {
	err = PTR_ERR(dir);
	goto err_out;
}

sub_fdt_dir = debugfs_create_dir("sub_fdts", dir);
if (IS_ERR(sub_fdt_dir)) {
	err = PTR_ERR(sub_fdt_dir);
	goto err_rmdir;
}

err = __kho_debugfs_blob_add(&dbg->fdt_list, dir, "fdt", fdt,
			     fdt_totalsize(fdt));
if (err)
	goto err_rmdir;

fdt_for_each_subnode(child, fdt, 0) {
	int len = 0;
	const char *name = fdt_get_name(fdt, child, NULL);
	const u64 *fdt_phys;
	void *sub_fdt;

	fdt_phys = fdt_getprop(fdt, child,
				KHO_SUB_TREE_PROP_NAME, &len);
	if (!fdt_phys)
		continue;
	if (len != sizeof(*fdt_phys)) {
		pr_warn("node %s prop fdt has invalid length: %d\n",
			name, len);
		continue;
	}
	sub_fdt = phys_to_virt(*fdt_phys);
	err = __kho_debugfs_blob_add(&dbg->fdt_list, sub_fdt_dir, name,
				     sub_fdt, fdt_totalsize(sub_fdt));
	if (err) {
		pr_warn("failed to add fdt %s to debugfs: %pe\n", name,
			ERR_PTR(err));
		continue;
	}
}

dbg->dir = dir;
dbg->sub_fdt_dir = sub_fdt_dir;

return;
err_rmdir:
debugfs_remove_recursive(dir);
err_out:
/*
 * Failure to create /sys/kernel/debug/kho/in does not prevent
 * reviving state from KHO and setting up KHO for the next
 * kexec.
 */
if (err) {
	pr_err("failed exposing handover FDT in debugfs: %pe\n",
	       ERR_PTR(err));
}
}
