Implement the following feature in the code below: sctp: fix sockets_allocated imbalance after sk_clone().

Feature description:
sk_clone() increments sockets_allocated and sets the socket refcount to 2.
SCTP performs additional accounting in sctp_clone_sock(), so the clone-time
increment must be undone to avoid double counting.

Note we cannot simply remove the SCTP-side increment, because the SCTP
destroy path in sctp_destroy_sock() only decrements sockets_allocated when
sp->ep is set, which may not be true for all failure paths in
sctp_clone_sock().

Output the complete corrected function(s).

```c
static struct sock *sctp_clone_sock(struct sock *sk,
			    struct sctp_association *asoc,
			    enum sctp_socket_type type)
{
struct sock *newsk = sk_clone(sk, GFP_KERNEL, false);
struct inet_sock *newinet;
struct sctp_sock *newsp;
int err = -ENOMEM;

if (!newsk)
	return ERR_PTR(err);

/* sk_clone() sets refcnt to 2 */
sock_put(newsk);

newinet = inet_sk(newsk);
newsp = sctp_sk(newsk);

newsp->pf->to_sk_daddr(&asoc->peer.primary_addr, newsk);
newinet->inet_dport = htons(asoc->peer.port);
atomic_set(&newinet->inet_id, get_random_u16());

inet_set_bit(MC_LOOP, newsk);
newinet->mc_ttl = 1;
newinet->mc_index = 0;
newinet->mc_list = NULL;

#if IS_ENABLED(CONFIG_IPV6)
if (sk->sk_family == AF_INET6) {
	struct ipv6_pinfo *newnp;

	newinet->pinet6 = &((struct sctp6_sock *)newsk)->inet6;
	newinet->ipv6_fl_list = NULL;

	newnp = inet6_sk(newsk);
	memcpy(newnp, inet6_sk(sk), sizeof(struct ipv6_pinfo));
	newnp->ipv6_mc_list = NULL;
	newnp->ipv6_ac_list = NULL;
}
#endif

newsp->pf->copy_ip_options(sk, newsk);

newsp->do_auto_asconf = 0;
skb_queue_head_init(&newsp->pd_lobby);

newsp->ep = sctp_endpoint_new(newsk, GFP_KERNEL);
if (!newsp->ep)
	goto out_release;

SCTP_DBG_OBJCNT_INC(sock);
sk_sockets_allocated_inc(newsk);
sock_prot_inuse_add(sock_net(sk), newsk->sk_prot, 1);

err = sctp_sock_migrate(sk, newsk, asoc, type);
if (err)
	goto out_release;

/* Set newsk security attributes from original sk and connection
 * security attribute from asoc.
 */
security_sctp_sk_clone(asoc, sk, newsk);

return newsk;

out_release:
sk_common_release(newsk);
return ERR_PTR(err);
}
```

