Implement the following feature in the code below: ublk: reject max_sectors smaller than PAGE_SECTORS in parameter validation.

Feature description:
blk_validate_limits() requires max_hw_sectors >= PAGE_SECTORS and fires
a WARN_ON_ONCE if this invariant is violated. ublk_validate_params()
only checked the upper bound of max_sectors against max_io_buf_bytes,
allowing userspace to pass small values (including zero) that trigger
the warning when blk_mq_alloc_disk() is called from
ublk_ctrl_start_dev().

Before 494ea040bcb5, ublk used blk_queue_max_hw_sectors() which silently
clamped small values up to PAGE_SECTORS. The conversion to passing
queue_limits directly to blk_mq_alloc_disk() lost that clamping and now
hits blk_validate_limits()'s WARN_ON_ONCE instead.

Validate that max_sectors is at least PAGE_SECTORS in
ublk_validate_params() so invalid values are rejected early with
-EINVAL instead of reaching the block layer.

Output the complete corrected function(s).

```c
static int ublk_validate_params(const struct ublk_device *ub)
{
/* basic param is the only one which must be set */
if (ub->params.types & UBLK_PARAM_TYPE_BASIC) {
	const struct ublk_param_basic *p = &ub->params.basic;

	if (p->logical_bs_shift > PAGE_SHIFT || p->logical_bs_shift < 9)
		return -EINVAL;

	/*
	 * 256M is a reasonable upper bound for physical block size,
	 * io_min and io_opt; it aligns with the maximum physical
	 * block size possible in NVMe.
	 */
	if (p->physical_bs_shift > ilog2(SZ_256M))
		return -EINVAL;

	if (p->io_min_shift > ilog2(SZ_256M))
		return -EINVAL;

	if (p->io_opt_shift > ilog2(SZ_256M))
		return -EINVAL;

	if (p->logical_bs_shift > p->physical_bs_shift)
		return -EINVAL;

	if (p->max_sectors > (ub->dev_info.max_io_buf_bytes >> 9))
		return -EINVAL;

	if (ublk_dev_is_zoned(ub) && !p->chunk_sectors)
		return -EINVAL;
} else
	return -EINVAL;

if (ub->params.types & UBLK_PARAM_TYPE_DISCARD) {
	const struct ublk_param_discard *p = &ub->params.discard;

	/* So far, only support single segment discard */
	if (p->max_discard_sectors && p->max_discard_segments != 1)
		return -EINVAL;

	if (!p->discard_granularity)
		return -EINVAL;
}

/* dev_t is read-only */
if (ub->params.types & UBLK_PARAM_TYPE_DEVT)
	return -EINVAL;

if (ub->params.types & UBLK_PARAM_TYPE_ZONED)
	return ublk_dev_param_zoned_validate(ub);
else if (ublk_dev_is_zoned(ub))
	return -EINVAL;

if (ub->params.types & UBLK_PARAM_TYPE_DMA_ALIGN) {
	const struct ublk_param_dma_align *p = &ub->params.dma;

	if (p->alignment >= PAGE_SIZE)
		return -EINVAL;

	if (!is_power_of_2(p->alignment + 1))
		return -EINVAL;
}

if (ub->params.types & UBLK_PARAM_TYPE_SEGMENT) {
	const struct ublk_param_segment *p = &ub->params.seg;

	if (!is_power_of_2(p->seg_boundary_mask + 1))
		return -EINVAL;

	if (p->seg_boundary_mask + 1 < UBLK_MIN_SEGMENT_SIZE)
		return -EINVAL;
	if (p->max_segment_size < UBLK_MIN_SEGMENT_SIZE)
		return -EINVAL;
}

if (ub->params.types & UBLK_PARAM_TYPE_INTEGRITY) {
	const struct ublk_param_integrity *p = &ub->params.integrity;
	int pi_tuple_size = ublk_integrity_pi_tuple_size(p->csum_type);
	int flags = ublk_integrity_flags(p->flags);

	if (!ublk_dev_support_integrity(ub))
		return -EINVAL;
	if (flags < 0)
		return flags;
	if (pi_tuple_size < 0)
		return pi_tuple_size;
	if (!p->metadata_size)
		return -EINVAL;
	if (p->csum_type == LBMD_PI_CSUM_NONE &&
	    p->flags & LBMD_PI_CAP_REFTAG)
		return -EINVAL;
	if (p->pi_offset + pi_tuple_size > p->metadata_size)
		return -EINVAL;
	if (p->interval_exp < SECTOR_SHIFT ||
	    p->interval_exp > ub->params.basic.logical_bs_shift)
		return -EINVAL;
}

return 0;
}
