Fix the following bug in the code below: ksmbd: fix OOB write in QUERY_INFO for compound requests.

Fix strategy: add error path; add error return

Problem description:
When a compound request such as READ + QUERY_INFO(Security) is received,
and the first command (READ) consumes most of the response buffer,
ksmbd could write beyond the allocated buffer while building a security
descriptor.

The root cause was that smb2_get_info_sec() checked buffer space using
ppntsd_size from xattr, while build_sec_desc() often synthesized a
significantly larger descriptor from POSIX ACLs.

This patch introduces smb_acl_sec_desc_scratch_len() to accurately
compute the final descriptor size beforehand, performs proper buffer
checking with smb2_calc_max_out_buf_len(), and uses exact-sized
allocation + iov pinning.

Output the complete corrected function(s).

```c
static int smb2_get_info_file(struct ksmbd_work *work,
		      struct smb2_query_info_req *req,
		      struct smb2_query_info_rsp *rsp)
{
struct ksmbd_file *fp;
int fileinfoclass = 0;
int rc = 0;
unsigned int id = KSMBD_NO_FID, pid = KSMBD_NO_FID;

if (test_share_config_flag(work->tcon->share_conf,
			   KSMBD_SHARE_FLAG_PIPE)) {
	/* smb2 info file called for pipe */
	return smb2_get_info_file_pipe(work->sess, req, rsp,
				       work->response_buf);
}

if (work->next_smb2_rcv_hdr_off) {
	if (!has_file_id(req->VolatileFileId)) {
		ksmbd_debug(SMB, "Compound request set FID = %llu\n",
			    work->compound_fid);
		id = work->compound_fid;
		pid = work->compound_pfid;
	}
}

if (!has_file_id(id)) {
	id = req->VolatileFileId;
	pid = req->PersistentFileId;
}

fp = ksmbd_lookup_fd_slow(work, id, pid);
if (!fp)
	return -ENOENT;

fileinfoclass = req->FileInfoClass;

switch (fileinfoclass) {
case FILE_ACCESS_INFORMATION:
	get_file_access_info(rsp, fp, work->response_buf);
	break;

case FILE_BASIC_INFORMATION:
	rc = get_file_basic_info(rsp, fp, work->response_buf);
	break;

case FILE_STANDARD_INFORMATION:
	rc = get_file_standard_info(rsp, fp, work->response_buf);
	break;

case FILE_ALIGNMENT_INFORMATION:
	get_file_alignment_info(rsp, work->response_buf);
	break;

case FILE_ALL_INFORMATION:
	rc = get_file_all_info(work, rsp, fp, work->response_buf);
	break;

case FILE_ALTERNATE_NAME_INFORMATION:
	get_file_alternate_info(work, rsp, fp, work->response_buf);
	break;

case FILE_STREAM_INFORMATION:
	rc = get_file_stream_info(work, rsp, fp, work->response_buf);
	break;

case FILE_INTERNAL_INFORMATION:
	rc = get_file_internal_info(rsp, fp, work->response_buf);
	break;

case FILE_NETWORK_OPEN_INFORMATION:
	rc = get_file_network_open_info(rsp, fp, work->response_buf);
	break;

case FILE_EA_INFORMATION:
	get_file_ea_info(rsp, work->response_buf);
	break;

case FILE_FULL_EA_INFORMATION:
	rc = smb2_get_ea(work, fp, req, rsp, work->response_buf);
	break;

case FILE_POSITION_INFORMATION:
	get_file_position_info(rsp, fp, work->response_buf);
	break;

case FILE_MODE_INFORMATION:
	get_file_mode_info(rsp, fp, work->response_buf);
	break;

case FILE_COMPRESSION_INFORMATION:
	rc = get_file_compression_info(rsp, fp, work->response_buf);
	break;

case FILE_ATTRIBUTE_TAG_INFORMATION:
	rc = get_file_attribute_tag_info(rsp, fp, work->response_buf);
	break;
case SMB_FIND_FILE_POSIX_INFO:
	if (!work->tcon->posix_extensions) {
		pr_err("client doesn't negotiate with SMB3.1.1 POSIX Extensions\n");
		rc = -EOPNOTSUPP;
	} else {
		rc = find_file_posix_info(rsp, fp, work->response_buf);
	}
	break;
default:
	ksmbd_debug(SMB, "fileinfoclass %d not supported yet\n",
		    fileinfoclass);
	rc = -EOPNOTSUPP;
}
if (!rc)
	rc = buffer_check_err(le32_to_cpu(req->OutputBufferLength),
			      rsp, work->response_buf);
ksmbd_fd_put(work, fp);
return rc;
}
