Explain the following Linux kernel function in detail. Describe what it does, its parameters, return value, and any important side effects.

Function (from kernel/signal.c):
```c
static int dequeue_synchronous_signal(kernel_siginfo_t *info)
{
	struct task_struct *tsk = current;
	struct sigpending *pending = &tsk->pending;
	struct sigqueue *q, *sync = NULL;

	/*
	 * Might a synchronous signal be in the queue?
	 */
	if (!((pending->signal.sig[0] & ~tsk->blocked.sig[0]) & SYNCHRONOUS_MASK))
		return 0;

	/*
	 * Return the first synchronous signal in the queue.
	 */
	list_for_each_entry(q, &pending->list, list) {
		/* Synchronous signals have a positive si_code */
		if ((q->info.si_code > SI_USER) &&
		    (sigmask(q->info.si_signo) & SYNCHRONOUS_MASK)) {
			sync = q;
			goto next;
		}
	}
	return 0;
next:
	/*
	 * Check if there is another siginfo for the same signal.
	 */
	list_for_each_entry_continue(q, &pending->list, list) {
		if (q->info.si_signo == sync->info.si_signo)
			goto still_pending;
	}

	sigdelset(&pending->signal, sync->info.si_signo);
	recalc_sigpending();
still_pending:
	list_del_init(&sync->list);
	copy_siginfo(info, &sync->info);
	__sigqueue_free(sync);
	return info->si_signo;
}
```

Refactor the following code: bus: stm32_firewall: Simplify with scoped for each OF child loop.

Refactoring description:
Use scoped for-each loop when iterating over device nodes to make code a
bit simpler.

Output the complete corrected function(s).

```c
int stm32_firewall_populate_bus(struct stm32_firewall_controller *firewall_controller)
{
struct stm32_firewall *firewalls;
struct device_node *child;
struct device *parent;
unsigned int i;
int len;
int err;

parent = firewall_controller->dev;

dev_dbg(parent, "Populating %s system bus\n", dev_name(firewall_controller->dev));

for_each_available_child_of_node(dev_of_node(parent), child) {
	/* The access-controllers property is mandatory for firewall bus devices */
	len = of_count_phandle_with_args(child, "access-controllers",
					 "#access-controller-cells");
	if (len <= 0) {
		of_node_put(child);
		return -EINVAL;
	}

	firewalls = kzalloc_objs(*firewalls, len);
	if (!firewalls) {
		of_node_put(child);
		return -ENOMEM;
	}

	err = stm32_firewall_get_firewall(child, firewalls, (unsigned int)len);
	if (err) {
		kfree(firewalls);
		of_node_put(child);
		return err;
	}

	for (i = 0; i < len; i++) {
		if (firewall_controller->grant_access(firewall_controller,
						      firewalls[i].firewall_id)) {
			/*
			 * Peripheral access not allowed or not defined.
			 * Mark the node as populated so platform bus won't probe it
			 */
			of_detach_node(child);
			dev_err(parent, "%s: Device driver will not be probed\n",
				child->full_name);
		}
	}

	kfree(firewalls);
}

return 0;
}
```

