Implement the following feature in the code below: clk: renesas: r9a06g032: Enable watchdog reset sources.

Feature description:
The watchdog timeout is signaled using an interrupt and, on this
interrupt, a software initiated reset is performed.

This software initiated reset performs, in the end, a hardware system
reset using SWRST_REQ of RSTCTRL register.

The watchdog itself is able to control directly the hardware system
reset without any operation done by the interrupt handler. This feature
allows the watchdog to not depend on the software to reset the system
when a watchdog timeout occurs.

Indeed, when the watchdog timeout occurs, the watchdog requests a system
reset using its own hardware dedicated line but this reset source is
disabled at the reset controller level.

To benefit of this feature and be robust against software issues, enable
watchdogs reset sources.

Output the complete corrected function(s).

```c
static int __init r9a06g032_clocks_probe(struct platform_device *pdev)
{
struct device *dev = &pdev->dev;
struct device_node *np = dev->of_node;
struct r9a06g032_priv *clocks;
struct clk **clks;
struct clk *mclk;
unsigned int i;
struct regbit uart_group_sel[2];
int error;

clocks = devm_kzalloc(dev, sizeof(*clocks), GFP_KERNEL);
clks = devm_kcalloc(dev, R9A06G032_CLOCK_COUNT, sizeof(struct clk *),
		    GFP_KERNEL);
if (!clocks || !clks)
	return -ENOMEM;

spin_lock_init(&clocks->lock);

clocks->data.clks = clks;
clocks->data.clk_num = R9A06G032_CLOCK_COUNT;

mclk = devm_clk_get(dev, "mclk");
if (IS_ERR(mclk))
	return PTR_ERR(mclk);

clocks->reg = devm_of_iomap(dev, np, 0, NULL);
if (IS_ERR(clocks->reg))
	return PTR_ERR(clocks->reg);

r9a06g032_init_h2mode(clocks);

/* Clear potentially pending resets */
writel(R9A06G032_SYSCTRL_WDA7RST_0 | R9A06G032_SYSCTRL_WDA7RST_1,
       clocks->reg + R9A06G032_SYSCTRL_RSTCTRL);
/* Allow software reset */
writel(R9A06G032_SYSCTRL_SWRST | R9A06G032_SYSCTRL_RSTEN_MRESET_EN,
       clocks->reg + R9A06G032_SYSCTRL_RSTEN);

error = devm_register_sys_off_handler(dev, SYS_OFF_MODE_RESTART, SYS_OFF_PRIO_HIGH,
				      r9a06g032_restart_handler, NULL);
if (error)
	dev_warn(dev, "couldn't register restart handler (%d)\n", error);

for (i = 0; i < ARRAY_SIZE(r9a06g032_clocks); ++i) {
	const struct r9a06g032_clkdesc *d = &r9a06g032_clocks[i];
	const char *parent_name = d->source ?
		__clk_get_name(clocks->data.clks[d->source - 1]) :
		__clk_get_name(mclk);
	struct clk *clk = NULL;

	switch (d->type) {
	case K_FFC:
		clk = clk_register_fixed_factor(NULL, d->name,
						parent_name, 0,
						d->ffc.mul,
						d->ffc.div);
		break;
	case K_GATE:
		clk = r9a06g032_register_gate(clocks, parent_name, d);
		break;
	case K_DIV:
		clk = r9a06g032_register_div(clocks, parent_name, d);
		break;
	case K_BITSEL:
		/* keep that selector register around */
		uart_group_sel[d->dual.group] = d->dual.sel;
		clk = r9a06g032_register_bitsel(clocks, parent_name, d);
		break;
	case K_DUALGATE:
		clk = r9a06g032_register_dualgate(clocks, parent_name,
						  d,
						  uart_group_sel[d->dual.group]);
		break;
	}
	clocks->data.clks[d->index] = clk;
}
error = of_clk_add_provider(np, of_clk_src_onecell_get, &clocks->data);
if (error)
	return error;

error = devm_add_action_or_reset(dev,
				r9a06g032_clocks_del_clk_provider, np);
if (error)
	return error;

error = r9a06g032_add_clk_domain(dev);
if (error)
	return error;

sysctrl_priv = clocks;

