Implement the following feature in the code below: mtd: rawnand: sunxi: do not count BBM bytes twice.

Feature description:
BBM is already part of USER_DATA section, so we should not remove it twice

This was working ok because we are on the safe size, advertising that
there was 2 bytes less available than in reality.

But we can't change old platforms, since it may lead to a different ECC
strength, so, introduce a legacy flag for old platforms, and switch the
new platforms to the correct count.

Output the complete corrected function(s).

```c
static int sunxi_nand_hw_ecc_ctrl_init(struct nand_chip *nand,
			       struct nand_ecc_ctrl *ecc,
			       struct device_node *np)
{
struct sunxi_nand_chip *sunxi_nand = to_sunxi_nand(nand);
struct sunxi_nfc *nfc = to_sunxi_nfc(nand->controller);
const u8 *strengths = nfc->caps->ecc_strengths;
struct mtd_info *mtd = nand_to_mtd(nand);
struct nand_device *nanddev = mtd_to_nanddev(mtd);
int nsectors;
int i;

if (nanddev->ecc.user_conf.flags & NAND_ECC_MAXIMIZE_STRENGTH) {
	int bytes;

	ecc->size = 1024;
	nsectors = mtd->writesize / ecc->size;

	/* Reserve 2 bytes for the BBM */
	bytes = (mtd->oobsize - 2) / nsectors;

	/* 4 non-ECC bytes are added before each ECC bytes section */
	bytes -= USER_DATA_SZ;

	/* and bytes has to be even. */
	if (bytes % 2)
		bytes--;

	ecc->strength = bytes * 8 / fls(8 * ecc->size);

	for (i = 0; i < nfc->caps->nstrengths; i++) {
		if (strengths[i] > ecc->strength)
			break;
	}

	if (!i)
		ecc->strength = 0;
	else
		ecc->strength = strengths[i - 1];
}

if (ecc->size != 512 && ecc->size != 1024)
	return -EINVAL;

/* Prefer 1k ECC chunk over 512 ones */
if (ecc->size == 512 && mtd->writesize > 512) {
	ecc->size = 1024;
	ecc->strength *= 2;
}

/* Add ECC info retrieval from DT */
for (i = 0; i < nfc->caps->nstrengths; i++) {
	if (ecc->strength <= strengths[i]) {
		/*
		 * Update ecc->strength value with the actual strength
		 * that will be used by the ECC engine.
		 */
		ecc->strength = strengths[i];
		break;
	}
}

if (i >= nfc->caps->nstrengths) {
	dev_err(nfc->dev, "unsupported strength\n");
	return -ENOTSUPP;
}

/* HW ECC always request ECC bytes for 1024 bytes blocks */
ecc->bytes = DIV_ROUND_UP(ecc->strength * fls(8 * 1024), 8);

/* HW ECC always work with even numbers of ECC bytes */
ecc->bytes = ALIGN(ecc->bytes, 2);

nsectors = mtd->writesize / ecc->size;

if (mtd->oobsize < ((ecc->bytes + USER_DATA_SZ) * nsectors))
	return -EINVAL;

ecc->read_oob = sunxi_nfc_hw_ecc_read_oob;
ecc->write_oob = sunxi_nfc_hw_ecc_write_oob;
mtd_set_ooblayout(mtd, &sunxi_nand_ooblayout_ops);

if (nfc->dmac || nfc->caps->has_mdma) {
	ecc->read_page = sunxi_nfc_hw_ecc_read_page_dma;
	ecc->read_subpage = sunxi_nfc_hw_ecc_read_subpage_dma;
	ecc->write_page = sunxi_nfc_hw_ecc_write_page_dma;
	nand->options |= NAND_USES_DMA;
} else {
	ecc->read_page = sunxi_nfc_hw_ecc_read_page;
	ecc->read_subpage = sunxi_nfc_hw_ecc_read_subpage;
	ecc->write_page = sunxi_nfc_hw_ecc_write_page;
}

/* TODO: support DMA for raw accesses and subpage write */
ecc->write_subpage = sunxi_nfc_hw_ecc_write_subpage;
ecc->read_oob_raw = nand_read_oob_std;
ecc->write_oob_raw = nand_write_oob_std;

sunxi_nand->ecc.ecc_ctl = NFC_ECC_MODE(nfc, i) | NFC_ECC_EXCEPTION |
			  NFC_ECC_PIPELINE | NFC_ECC_EN;

if (ecc->size == 512) {
	if (nfc->caps->has_ecc_block_512) {
		sunxi_nand->ecc.ecc_ctl |= NFC_ECC_BLOCK_512;
	} else {
		dev_err(nfc->dev, "512B ECC block not supported\n");
		return -EOPNOTSUPP;
	}
}

return 0;
}
