Refactor the following code: powercap: intel_rapl: Remove unused AVERAGE_POWER primitive.

Refactoring description:
The AVERAGE_POWER primitive and RAPL_PRIMITIVE_DERIVED flag are not
used anywhere in the code.

Remove them to simplify the primitive handling logic.

No functional changes.

Output the complete corrected function(s).

```c
/* Read primitive data based on its related struct rapl_primitive_info.
* if xlate flag is set, return translated data based on data units, i.e.
* time, energy, and power.
* RAPL MSRs are non-architectual and are laid out not consistently across
* domains. Here we use primitive info to allow writing consolidated access
* functions.
* For a given primitive, it is processed by MSR mask and shift. Unit conversion
* is pre-assigned based on RAPL unit MSRs read at init time.
* 63-------------------------- 31--------------------------- 0
* |                           xxxxx (mask)                   |
* |                                |<- shift ----------------|
* 63-------------------------- 31--------------------------- 0
*/
static int rapl_read_data_raw(struct rapl_domain *rd,
			     enum rapl_primitives prim, bool xlate, u64 *data,
			     bool pmu_ctx)
{
       u64 value;
       enum rapl_primitives prim_fixed = prim_fixups(rd, prim);
       struct rapl_primitive_info *rpi = get_rpi(rd->rp, prim_fixed);
       struct reg_action ra;

       if (!rpi || !rpi->name || rpi->flag & RAPL_PRIMITIVE_DUMMY)
	       return -EINVAL;

       ra.reg = rd->regs[rpi->id];
       if (!ra.reg.val)
	       return -EINVAL;

       /* non-hardware data are collected by the polling thread */
       if (rpi->flag & RAPL_PRIMITIVE_DERIVED) {
	       *data = rd->rdd.primitives[prim];
	       return 0;
       }

       ra.mask = rpi->mask;

       if (rd->rp->priv->read_raw(get_rid(rd->rp), &ra, pmu_ctx)) {
	       pr_debug("failed to read reg 0x%llx for %s:%s\n", ra.reg.val, rd->rp->name, rd->name);
	       return -EIO;
       }

       value = ra.value >> rpi->shift;

       if (xlate)
	       *data = rapl_unit_xlate(rd, rpi->unit, value, 0);
       else
	       *data = value;

       return 0;
}
```

