Implement the following feature in the code below: ACPI: TAD: Create one attribute group.

Feature description:
Instead of creating three attribute groups, one for each supported
subset of capabilities, create just one and use an .is_visible()
callback in it to decide which attributes to use.

No intentional functional impact.

Output the complete corrected function(s).

```c
static int acpi_tad_probe(struct platform_device *pdev)
{
struct device *dev = &pdev->dev;
acpi_handle handle = ACPI_HANDLE(dev);
struct acpi_tad_driver_data *dd;
acpi_status status;
unsigned long long caps;
int ret;

/*
 * Initialization failure messages are mostly about firmware issues, so
 * print them at the "info" level.
 */
status = acpi_evaluate_integer(handle, "_GCP", NULL, &caps);
if (ACPI_FAILURE(status)) {
	dev_info(dev, "Unable to get capabilities\n");
	return -ENODEV;
}

if (!(caps & ACPI_TAD_AC_WAKE)) {
	dev_info(dev, "Unsupported capabilities\n");
	return -ENODEV;
}

if (!acpi_has_method(handle, "_PRW")) {
	dev_info(dev, "Missing _PRW\n");
	return -ENODEV;
}

dd = devm_kzalloc(dev, sizeof(*dd), GFP_KERNEL);
if (!dd)
	return -ENOMEM;

dd->capabilities = caps;
dev_set_drvdata(dev, dd);

/*
 * Assume that the ACPI PM domain has been attached to the device and
 * simply enable system wakeup and runtime PM and put the device into
 * runtime suspend.  Everything else should be taken care of by the ACPI
 * PM domain callbacks.
 */
device_init_wakeup(dev, true);
dev_pm_set_driver_flags(dev, DPM_FLAG_SMART_SUSPEND |
			     DPM_FLAG_MAY_SKIP_RESUME);
/*
 * The platform bus type layer tells the ACPI PM domain powers up the
 * device, so set the runtime PM status of it to "active".
 */
pm_runtime_set_active(dev);
pm_runtime_enable(dev);
pm_runtime_suspend(dev);

ret = sysfs_create_group(&dev->kobj, &acpi_tad_attr_group);
if (ret)
	goto fail;

if (caps & ACPI_TAD_DC_WAKE) {
	ret = sysfs_create_group(&dev->kobj, &acpi_tad_dc_attr_group);
	if (ret)
		goto fail;
}

if (caps & ACPI_TAD_RT) {
	ret = sysfs_create_group(&dev->kobj, &acpi_tad_time_attr_group);
	if (ret)
		goto fail;
}

return 0;

fail:
acpi_tad_remove(pdev);
return ret;
}
```

