Fix the following bug in the code below: wifi: mt76: mt7996: fix issues with manually triggered radar detection.

Fix strategy: add error return

Problem description:
Disallow triggering radar detection on non-DFS channels to prevent paused
TX queues from failing to resume, as a channel switch is not performed in
this case.

Output the complete corrected function(s).

```c
static int
mt7996_radar_trigger(void *data, u64 val)
{
#define RADAR_MAIN_CHAIN	1
#define RADAR_BACKGROUND	2
	struct mt7996_dev *dev = data;
	struct mt7996_phy *phy = mt7996_band_phy(dev, NL80211_BAND_5GHZ);
	int rdd_idx;

	if (!phy || !val || val > RADAR_BACKGROUND)
		return -EINVAL;

	if (val == RADAR_BACKGROUND && !dev->rdd2_phy) {
		dev_err(dev->mt76.dev, "Background radar is not enabled\n");
		return -EINVAL;
	}

	rdd_idx = mt7996_get_rdd_idx(phy, val == RADAR_BACKGROUND);
	if (rdd_idx < 0) {
		dev_err(dev->mt76.dev, "No RDD found\n");
		return -EINVAL;
	}

	return mt7996_mcu_rdd_cmd(dev, RDD_RADAR_EMULATE, rdd_idx, 0);
}
```

```c
static int
mt7996_radar_trigger(void *data, u64 val)
{
#define RADAR_MAIN_CHAIN	1
#define RADAR_BACKGROUND	2
	struct mt7996_dev *dev = data;
	struct mt7996_phy *phy = mt7996_band_phy(dev, NL80211_BAND_5GHZ);
	struct cfg80211_chan_def *chandef;
	int rdd_idx, ret;

	if (!phy || !val || val > RADAR_BACKGROUND)
		return -EINVAL;

	if (test_bit(MT76_SCANNING, &phy->mt76->state))
		return -EBUSY;

	if (val == RADAR_BACKGROUND) {
		if (!dev->rdd2_phy || !cfg80211_chandef_valid(&dev->rdd2_chandef)) {
			dev_err(dev->mt76.dev, "Background radar is not enabled\n");
			return -EINVAL;
		}
		chandef = &dev->rdd2_chandef;
	} else {
		chandef = &phy->mt76->chandef;
	}

	rdd_idx = mt7996_get_rdd_idx(phy, val == RADAR_BACKGROUND);
	if (rdd_idx < 0) {
		dev_err(dev->mt76.dev, "No RDD found\n");
		return -EINVAL;
	}

	ret = cfg80211_chandef_dfs_required(dev->mt76.hw->wiphy, chandef,
					    NL80211_IFTYPE_AP);
	if (ret <= 0)
		return ret;

	return mt7996_mcu_rdd_cmd(dev, RDD_RADAR_EMULATE, rdd_idx, 0);
}
```

Refactor the following code: media: rzv2h-ivc: Replace workqueue with direct function call.

Refactoring description:
Scheduling of work items with an async workqueue opens the door to
potential races between multiple instances of a work item.

While the frame transfer function is now protected against races, using
a workqueue doesn't provide much benefit considering the limited cost of
creating a job transfer.

Replace the usage of the work queue with direct function calls.

Output the complete corrected function(s).

```c
int rzv2h_ivc_init_vdev(struct rzv2h_ivc *ivc, struct v4l2_device *v4l2_dev)
{
struct v4l2_pix_format_mplane pix = { };
struct video_device *vdev;
struct vb2_queue *vb2q;
int ret;

spin_lock_init(&ivc->buffers.lock);
INIT_LIST_HEAD(&ivc->buffers.queue);
INIT_WORK(&ivc->buffers.work, rzv2h_ivc_transfer_buffer);

ivc->buffers.async_wq = alloc_workqueue("rzv2h-ivc", 0, 0);
if (!ivc->buffers.async_wq)
	return -EINVAL;

/* Initialise vb2 queue */
vb2q = &ivc->vdev.vb2q;
vb2q->type = V4L2_BUF_TYPE_VIDEO_OUTPUT_MPLANE;
vb2q->io_modes = VB2_MMAP | VB2_DMABUF;
vb2q->drv_priv = ivc;
vb2q->mem_ops = &vb2_dma_contig_memops;
vb2q->ops = &rzv2h_ivc_vb2_ops;
vb2q->buf_struct_size = sizeof(struct rzv2h_ivc_buf);
vb2q->min_queued_buffers = 0;
vb2q->timestamp_flags = V4L2_BUF_FLAG_TIMESTAMP_MONOTONIC;
vb2q->lock = &ivc->lock;
vb2q->dev = ivc->dev;

ret = vb2_queue_init(vb2q);
if (ret) {
	dev_err(ivc->dev, "vb2 queue init failed\n");
	goto err_destroy_workqueue;
}

/* Initialise Video Device */
vdev = &ivc->vdev.dev;
strscpy(vdev->name, "rzv2h-ivc", sizeof(vdev->name));
vdev->release = video_device_release_empty;
vdev->fops = &rzv2h_ivc_v4l2_fops;
vdev->ioctl_ops = &rzv2h_ivc_v4l2_ioctl_ops;
vdev->lock = &ivc->lock;
vdev->v4l2_dev = v4l2_dev;
vdev->queue = vb2q;
vdev->device_caps = V4L2_CAP_VIDEO_OUTPUT_MPLANE | V4L2_CAP_STREAMING;
vdev->vfl_dir = VFL_DIR_TX;
video_set_drvdata(vdev, ivc);

pix.pixelformat = V4L2_PIX_FMT_SRGGB16;
pix.width = RZV2H_IVC_DEFAULT_WIDTH;
pix.height = RZV2H_IVC_DEFAULT_HEIGHT;
rzv2h_ivc_set_format(ivc, &pix);

ivc->vdev.pad.flags = MEDIA_PAD_FL_SOURCE;
ret = media_entity_pads_init(&ivc->vdev.dev.entity, 1, &ivc->vdev.pad);
if (ret)
	goto err_release_vb2q;

ret = video_register_device(vdev, VFL_TYPE_VIDEO, -1);
if (ret) {
	dev_err(ivc->dev, "failed to register IVC video device\n");
	goto err_cleanup_vdev_entity;
}

ret = media_create_pad_link(&vdev->entity, 0, &ivc->subdev.sd.entity,
			    RZV2H_IVC_SUBDEV_SINK_PAD,
			    MEDIA_LNK_FL_ENABLED |
			    MEDIA_LNK_FL_IMMUTABLE);
if (ret) {
	dev_err(ivc->dev, "failed to create media link\n");
	goto err_unregister_vdev;
}

return 0;

err_unregister_vdev:
video_unregister_device(vdev);
err_cleanup_vdev_entity:
media_entity_cleanup(&vdev->entity);
err_release_vb2q:
vb2_queue_release(vb2q);
err_destroy_workqueue:
destroy_workqueue(ivc->buffers.async_wq);

return ret;
}
