Implement the following feature in the code below: ipv6: sit: remove redundant ret = 0 assignment.

Feature description:
The variable ret is assigned a value at all places where it is used;
There is no need to assign a value when it is initially defined.

Output the complete corrected function(s).

```c
static int ipip6_tunnel_get_prl(struct net_device *dev, struct ip_tunnel_prl __user *a)
{
struct ip_tunnel *t = netdev_priv(dev);
struct ip_tunnel_prl kprl, *kp;
struct ip_tunnel_prl_entry *prl;
unsigned int cmax, c = 0, ca, len;
int ret = 0;

if (dev == dev_to_sit_net(dev)->fb_tunnel_dev)
	return -EINVAL;

if (copy_from_user(&kprl, a, sizeof(kprl)))
	return -EFAULT;
cmax = kprl.datalen / sizeof(kprl);
if (cmax > 1 && kprl.addr != htonl(INADDR_ANY))
	cmax = 1;

/* For simple GET or for root users,
 * we try harder to allocate.
 */
kp = (cmax <= 1 || capable(CAP_NET_ADMIN)) ?
	kzalloc_objs(*kp, cmax, GFP_KERNEL_ACCOUNT | __GFP_NOWARN) :
	NULL;

ca = min(t->prl_count, cmax);

if (!kp) {
	/* We don't try hard to allocate much memory for
	 * non-root users.
	 * For root users, retry allocating enough memory for
	 * the answer.
	 */
	kp = kzalloc_objs(*kp, ca,
			  GFP_ATOMIC | __GFP_ACCOUNT | __GFP_NOWARN);
	if (!kp) {
		ret = -ENOMEM;
		goto out;
	}
}

rcu_read_lock();
for_each_prl_rcu(t->prl) {
	if (c >= cmax)
		break;
	if (kprl.addr != htonl(INADDR_ANY) && prl->addr != kprl.addr)
		continue;
	kp[c].addr = prl->addr;
	kp[c].flags = prl->flags;
	c++;
	if (kprl.addr != htonl(INADDR_ANY))
		break;
}

rcu_read_unlock();

len = sizeof(*kp) * c;
ret = 0;
if ((len && copy_to_user(a + 1, kp, len)) || put_user(len, &a->datalen))
	ret = -EFAULT;

kfree(kp);
out:
return ret;
}
