			    NETLINK_CB(cb->skb).portid,
			    cb->nlh->nlmsg_seq,
			    RTM_NEWNEIGH,
			    NLM_F_MULTI);
	if (err < 0)
		break;
skip:
	*idx += 1;
}
rcu_read_unlock();

return err;
