int xt_check_match(struct xt_mtchk_param *par,
	   unsigned int size, u16 proto, bool inv_proto)
{
int ret;

if (XT_ALIGN(par->match->matchsize) != size &&
    par->match->matchsize != -1) {
	/*
	 * ebt_among is exempt from centralized matchsize checking
	 * because it uses a dynamic-size data set.
	 */
	pr_err_ratelimited("%s_tables: %s.%u match: invalid size %u (kernel) != (user) %u\n",
			   xt_prefix[par->family], par->match->name,
			   par->match->revision,
			   XT_ALIGN(par->match->matchsize), size);
	return -EINVAL;
}
if (par->match->table != NULL &&
    strcmp(par->match->table, par->table) != 0) {
	pr_info_ratelimited("%s_tables: %s match: only valid in %s table, not %s\n",
			    xt_prefix[par->family], par->match->name,
			    par->match->table, par->table);
	return -EINVAL;
}

/* NFPROTO_UNSPEC implies NF_INET_* hooks which do not overlap with
 * NF_ARP_IN,OUT,FORWARD, allow explicit extensions with NFPROTO_ARP
 * support.
 */
if (par->family == NFPROTO_ARP &&
    par->match->family != NFPROTO_ARP) {
	pr_info_ratelimited("%s_tables: %s match: not valid for this family\n",
			    xt_prefix[par->family], par->match->name);
	return -EINVAL;
}
if (par->match->hooks && (par->hook_mask & ~par->match->hooks) != 0) {
	char used[64], allow[64];

	pr_info_ratelimited("%s_tables: %s match: used from hooks %s, but only valid from %s\n",
			    xt_prefix[par->family], par->match->name,
			    textify_hooks(used, sizeof(used),
					  par->hook_mask, par->family),
			    textify_hooks(allow, sizeof(allow),
					  par->match->hooks,
					  par->family));
	return -EINVAL;
}
if (par->match->proto && (par->match->proto != proto || inv_proto)) {
	pr_info_ratelimited("%s_tables: %s match: only valid for protocol %u\n",
			    xt_prefix[par->family], par->match->name,
			    par->match->proto);
	return -EINVAL;
}
if (par->match->checkentry != NULL) {
	ret = par->match->checkentry(par);
	if (ret < 0)
		return ret;
	else if (ret > 0)
		/* Flag up potential errors. */
		return -EIO;
}
return 0;
}
