stock->nr_bytes += nr_bytes;

if (pgdat)
	__account_obj_stock(objcg, stock, nr_acct, pgdat, idx);

if (allow_uncharge && (stock->nr_bytes > PAGE_SIZE)) {
	nr_pages = stock->nr_bytes >> PAGE_SHIFT;
	stock->nr_bytes &= (PAGE_SIZE - 1);
