Refactor the following code: ASoC: sun4i-spdif: Make reset control non-optional and check for all errors.

Refactor strategy: add error pointer handling

Refactoring description:
The logic around the reset control is weird. The driver already has
quirks describing which compatible strings require a reset control, but
the reset control is acquired using the "optional" API. Then any errors
other than deferred probe are ignored.

Instead, switch to the non-optional variant. Also use the deassered
variant to simplify the code. This also fixes a missing reset assert
upon removal.

Last, clean up the error message printing with dev_err_probe().

Output the complete corrected function(s).

```c
static int sun4i_spdif_probe(struct platform_device *pdev)
{
struct sun4i_spdif_dev *host;
struct resource *res;
const struct sun4i_spdif_quirks *quirks;
int ret;
void __iomem *base;
const char *tx_clk_name = "spdif";

dev_dbg(&pdev->dev, "Entered %s\n", __func__);

host = devm_kzalloc(&pdev->dev, sizeof(*host), GFP_KERNEL);
if (!host)
	return -ENOMEM;

host->pdev = pdev;
spin_lock_init(&host->lock);

/* Initialize this copy of the CPU DAI driver structure */
memcpy(&host->cpu_dai_drv, &sun4i_spdif_dai, sizeof(sun4i_spdif_dai));
host->cpu_dai_drv.name = dev_name(&pdev->dev);

/* Get the addresses */
base = devm_platform_get_and_ioremap_resource(pdev, 0, &res);
if (IS_ERR(base))
	return PTR_ERR(base);

quirks = of_device_get_match_data(&pdev->dev);
if (quirks == NULL) {
	dev_err(&pdev->dev, "Failed to determine the quirks to use\n");
	return -ENODEV;
}
host->quirks = quirks;

host->regmap = devm_regmap_init_mmio(&pdev->dev, base,
					&sun4i_spdif_regmap_config);
if (IS_ERR(host->regmap)) {
	dev_err(&pdev->dev, "failed to initialise regmap.\n");
	return PTR_ERR(host->regmap);
}

/* Clocks */
host->apb_clk = devm_clk_get(&pdev->dev, "apb");
if (IS_ERR(host->apb_clk)) {
	dev_err(&pdev->dev, "failed to get a apb clock.\n");
	return PTR_ERR(host->apb_clk);
}

if (quirks->tx_clk_name)
	tx_clk_name = quirks->tx_clk_name;
host->spdif_clk = devm_clk_get(&pdev->dev, tx_clk_name);
if (IS_ERR(host->spdif_clk)) {
	dev_err(&pdev->dev, "failed to get the \"%s\" clock.\n",
		tx_clk_name);
	return PTR_ERR(host->spdif_clk);
}

host->dma_params_tx.addr = res->start + quirks->reg_dac_txdata;
host->dma_params_tx.maxburst = 8;
host->dma_params_tx.addr_width = DMA_SLAVE_BUSWIDTH_2_BYTES;

platform_set_drvdata(pdev, host);

if (quirks->has_reset) {
	host->rst = devm_reset_control_get_optional_exclusive(&pdev->dev,
							      NULL);
	if (PTR_ERR(host->rst) == -EPROBE_DEFER) {
		ret = -EPROBE_DEFER;
		dev_err(&pdev->dev, "Failed to get reset: %d\n", ret);
		return ret;
	}
	if (!IS_ERR(host->rst))
		reset_control_deassert(host->rst);
}

ret = devm_snd_soc_register_component(&pdev->dev,
			&sun4i_spdif_component, &sun4i_spdif_dai, 1);
if (ret)
	return ret;

pm_runtime_enable(&pdev->dev);
if (!pm_runtime_enabled(&pdev->dev)) {
	ret = sun4i_spdif_runtime_resume(&pdev->dev);
	if (ret)
		goto err_unregister;
}

ret = devm_snd_dmaengine_pcm_register(&pdev->dev, NULL, 0);
if (ret)
	goto err_suspend;
return 0;
err_suspend:
if (!pm_runtime_status_suspended(&pdev->dev))
	sun4i_spdif_runtime_suspend(&pdev->dev);
err_unregister:
pm_runtime_disable(&pdev->dev);
return ret;
}
