       stepping = fms & 0xf;
       if (family == 6 || family == 0xf)
	       model += ((fms >> 16) & 0xf) << 4;

       if (debug) {
	       fprintf(stderr, "%d CPUID levels; family:model:stepping 0x%x:%x:%x (%d:%d:%d)\n",
		       max_level, family, model, stepping, family, model, stepping);
	       fprintf(stderr, "CPUID(1): %s %s %s %s %s %s %s %s\n",
		       ecx & (1 << 0) ? "SSE3" : "-",
		       ecx & (1 << 3) ? "MONITOR" : "-",
		       ecx & (1 << 7) ? "EIST" : "-",
		       ecx & (1 << 8) ? "TM2" : "-",
		       edx & (1 << 4) ? "TSC" : "-",
		       edx & (1 << 5) ? "MSR" : "-",
		       edx & (1 << 22) ? "ACPI-TM" : "-",
		       edx & (1 << 29) ? "TM" : "-");
       }

       if (!(edx & (1 << 5)))
	       errx(1, "CPUID: no MSR");


       get_cpuid_or_exit(0x6, &eax, &ebx, &ecx, &edx);
       /* turbo_is_enabled already set */
       /* has_hwp already set */
       has_hwp_notify = eax & (1 << 8);
       has_hwp_activity_window = eax & (1 << 9);
       has_hwp_epp = eax & (1 << 10);
       has_hwp_request_pkg = eax & (1 << 11);

       if (!has_hwp_request_pkg && update_hwp_use_pkg)
	       errx(1, "--hwp-use-pkg is not available on this hardware");

       /* has_epb already set */

       if (debug)
	       fprintf(stderr,
		       "CPUID(6): %sTURBO, %sHWP, %sHWPnotify, %sHWPwindow, %sHWPepp, %sHWPpkg, %sEPB\n",
