static u32 get_ae_mask(struct adf_hw_device_data *self)
{
unsigned long fuses = self->fuses[ADF_FUSECTL4];
u32 mask = ADF_420XX_ACCELENGINES_MASK;

if (test_bit(0, &fuses))
	mask &= ~ADF_AE_GROUP_0;

if (test_bit(4, &fuses))
	mask &= ~ADF_AE_GROUP_1;

if (test_bit(8, &fuses))
	mask &= ~ADF_AE_GROUP_2;

if (test_bit(12, &fuses))
	mask &= ~ADF_AE_GROUP_3;

if (test_bit(16, &fuses))
	mask &= ~ADF_AE_GROUP_4;

return mask;
}
