Refactor the following code: net: mana: Use pci_name() for debugfs directory naming.

Refactoring description:
Use pci_name(pdev) for the per-device debugfs directory instead of
hardcoded "0" for PFs and pci_slot_name(pdev->slot) for VFs. The
previous approach had two issues:

1. pci_slot_name() dereferences pdev->slot, which can be NULL for VFs
   in environments like generic VFIO passthrough or nested KVM,
   causing a NULL pointer dereference.

2. Multiple PFs would all use "0", and VFs across different PCI
   domains or buses could share the same slot name, leading to
   -EEXIST errors from debugfs_create_dir().

pci_name(pdev) returns the unique BDF address, is always valid, and is
unique across the system.

Output the complete corrected function(s).

```c
static int mana_gd_probe(struct pci_dev *pdev, const struct pci_device_id *ent)
{
struct gdma_context *gc;
void __iomem *bar0_va;
int bar = 0;
int err;

/* Each port has 2 CQs, each CQ has at most 1 EQE at a time */
BUILD_BUG_ON(2 * MAX_PORTS_IN_MANA_DEV * GDMA_EQE_SIZE > EQ_SIZE);

err = pci_enable_device(pdev);
if (err) {
	dev_err(&pdev->dev, "Failed to enable pci device (err=%d)\n", err);
	return -ENXIO;
}

pci_set_master(pdev);

err = pci_request_regions(pdev, "mana");
if (err)
	goto disable_dev;

err = dma_set_mask_and_coherent(&pdev->dev, DMA_BIT_MASK(64));
if (err) {
	dev_err(&pdev->dev, "DMA set mask failed: %d\n", err);
	goto release_region;
}
dma_set_max_seg_size(&pdev->dev, UINT_MAX);

err = -ENOMEM;
gc = vzalloc(sizeof(*gc));
if (!gc)
	goto release_region;

mutex_init(&gc->eq_test_event_mutex);
pci_set_drvdata(pdev, gc);
gc->bar0_pa = pci_resource_start(pdev, 0);

bar0_va = pci_iomap(pdev, bar, 0);
if (!bar0_va)
	goto free_gc;

gc->numa_node = dev_to_node(&pdev->dev);
gc->is_pf = mana_is_pf(pdev->device);
gc->bar0_va = bar0_va;
gc->dev = &pdev->dev;
xa_init(&gc->irq_contexts);

if (gc->is_pf)
	gc->mana_pci_debugfs = debugfs_create_dir("0", mana_debugfs_root);
else
	gc->mana_pci_debugfs = debugfs_create_dir(pci_slot_name(pdev->slot),
						  mana_debugfs_root);

err = mana_gd_setup(pdev);
if (err)
	goto unmap_bar;

err = mana_probe(&gc->mana, false);
if (err)
	goto cleanup_gd;

err = mana_rdma_probe(&gc->mana_ib);
if (err)
	goto cleanup_mana;

/*
 * If a hardware reset event has occurred over HWC during probe,
 * rollback and perform hardware reset procedure.
 */
if (test_and_set_bit(GC_PROBE_SUCCEEDED, &gc->flags)) {
	err = -EPROTO;
	goto cleanup_mana_rdma;
}

return 0;

cleanup_mana_rdma:
mana_rdma_remove(&gc->mana_ib);
cleanup_mana:
mana_remove(&gc->mana, false);
cleanup_gd:
mana_gd_cleanup(pdev);
unmap_bar:
/*
 * at this point we know that the other debugfs child dir/files
 * are either not yet created or are already cleaned up.
 * The pci debugfs folder clean-up now, will only be cleaning up
 * adapter-MTU file and apc->mana_pci_debugfs folder.
