Implement the following feature in the code below: Do not always generate an ACK for some netlink operations.

Feature description:
In rdma_nl_rcv_skb(), the local variable err is assigned the return value
of the supplied callback function, which could be one of
ib_nl_handle_resolve_resp(), ib_nl_handle_set_timeout(), or
ib_nl_handle_ip_res_resp(). These three functions all return skb->len on
success.

rdma_nl_rcv_skb() is merely a copy of netlink_rcv_skb(). The callback
functions used by the latter have the convention: "Returns 0 on success or
a negative error code".

In particular, the statement (equal for both functions):

   if (nlh->nlmsg_flags & NLM_F_ACK || err)

implies that rdma_nl_rcv_skb() always will ack a message, independent of
the NLM_F_ACK being set in nlmsg_flags or not.

The fix could be to change the above statement, but it is better to keep
the two *_rcv_skb() functions equal in this respect and instead change the
three callback functions in the rdma subsystem to the correct convention.

Output the complete corrected function(s).

```c
int ib_nl_handle_set_timeout(struct sk_buff *skb,
		     struct nlmsghdr *nlh,
		     struct netlink_ext_ack *extack)
{
int timeout, delta, abs_delta;
const struct nlattr *attr;
unsigned long flags;
struct ib_sa_query *query;
long delay = 0;
struct nlattr *tb[LS_NLA_TYPE_MAX];
int ret;

if (!(nlh->nlmsg_flags & NLM_F_REQUEST) ||
    !(NETLINK_CB(skb).sk))
	return -EPERM;

ret = nla_parse_deprecated(tb, LS_NLA_TYPE_MAX - 1, nlmsg_data(nlh),
			   nlmsg_len(nlh), ib_nl_policy, NULL);
attr = (const struct nlattr *)tb[LS_NLA_TYPE_TIMEOUT];
if (ret || !attr)
	goto settimeout_out;

timeout = *(int *) nla_data(attr);
if (timeout < IB_SA_LOCAL_SVC_TIMEOUT_MIN)
	timeout = IB_SA_LOCAL_SVC_TIMEOUT_MIN;
if (timeout > IB_SA_LOCAL_SVC_TIMEOUT_MAX)
	timeout = IB_SA_LOCAL_SVC_TIMEOUT_MAX;

delta = timeout - sa_local_svc_timeout_ms;
if (delta < 0)
	abs_delta = -delta;
else
	abs_delta = delta;

if (delta != 0) {
	spin_lock_irqsave(&ib_nl_request_lock, flags);
	sa_local_svc_timeout_ms = timeout;
	list_for_each_entry(query, &ib_nl_request_list, list) {
		if (delta < 0 && abs_delta > query->timeout)
			query->timeout = 0;
		else
			query->timeout += delta;

		/* Get the new delay from the first entry */
		if (!delay) {
			delay = query->timeout - jiffies;
			if (delay <= 0)
				delay = 1;
		}
	}
	if (delay)
		mod_delayed_work(ib_nl_wq, &ib_nl_timed_work,
				 (unsigned long)delay);
	spin_unlock_irqrestore(&ib_nl_request_lock, flags);
}

settimeout_out:
return skb->len;
}
```

