Refactor the following code: seg6: separate dst_cache for input and output paths in seg6 lwtunnel.

Refactor strategy: add cleanup/free

Refactoring description:
The seg6 lwtunnel uses a single dst_cache per encap route, shared
between seg6_input_core() and seg6_output_core(). These two paths
can perform the post-encap SID lookup in different routing contexts
(e.g., ip rules matching on the ingress interface, or VRF table
separation). Whichever path runs first populates the cache, and the
other reuses it blindly, bypassing its own lookup.

Fix this by splitting the cache into cache_input and cache_output,
so each path maintains its own cached dst independently.

Output the complete corrected function(s).

```c
static int seg6_build_state(struct net *net, struct nlattr *nla,
		    unsigned int family, const void *cfg,
		    struct lwtunnel_state **ts,
		    struct netlink_ext_ack *extack)
{
struct nlattr *tb[SEG6_IPTUNNEL_MAX + 1];
struct seg6_iptunnel_encap *tuninfo;
struct lwtunnel_state *newts;
int tuninfo_len, min_size;
struct seg6_lwt *slwt;
int err;

if (family != AF_INET && family != AF_INET6)
	return -EINVAL;

err = nla_parse_nested_deprecated(tb, SEG6_IPTUNNEL_MAX, nla,
				  seg6_iptunnel_policy, extack);

if (err < 0)
	return err;

if (!tb[SEG6_IPTUNNEL_SRH])
	return -EINVAL;

tuninfo = nla_data(tb[SEG6_IPTUNNEL_SRH]);
tuninfo_len = nla_len(tb[SEG6_IPTUNNEL_SRH]);

/* tuninfo must contain at least the iptunnel encap structure,
 * the SRH and one segment
 */
min_size = sizeof(*tuninfo) + sizeof(struct ipv6_sr_hdr) +
	   sizeof(struct in6_addr);
if (tuninfo_len < min_size)
	return -EINVAL;

switch (tuninfo->mode) {
case SEG6_IPTUN_MODE_INLINE:
	if (family != AF_INET6)
		return -EINVAL;

	break;
case SEG6_IPTUN_MODE_ENCAP:
	break;
case SEG6_IPTUN_MODE_L2ENCAP:
	break;
case SEG6_IPTUN_MODE_ENCAP_RED:
	break;
case SEG6_IPTUN_MODE_L2ENCAP_RED:
	break;
default:
	return -EINVAL;
}

/* verify that SRH is consistent */
if (!seg6_validate_srh(tuninfo->srh, tuninfo_len - sizeof(*tuninfo), false))
	return -EINVAL;

newts = lwtunnel_state_alloc(tuninfo_len + sizeof(*slwt));
if (!newts)
	return -ENOMEM;

slwt = seg6_lwt_lwtunnel(newts);

err = dst_cache_init(&slwt->cache, GFP_ATOMIC);
if (err) {
	kfree(newts);
	return err;
}

memcpy(&slwt->tuninfo, tuninfo, tuninfo_len);

newts->type = LWTUNNEL_ENCAP_SEG6;
newts->flags |= LWTUNNEL_STATE_INPUT_REDIRECT;

if (tuninfo->mode != SEG6_IPTUN_MODE_L2ENCAP)
	newts->flags |= LWTUNNEL_STATE_OUTPUT_REDIRECT;

newts->headroom = seg6_lwt_headroom(tuninfo);

*ts = newts;

return 0;
}
