Refactor the following code: can: raw: convert to getsockopt_iter.

Refactoring description:
Convert CAN raw socket's getsockopt implementation to use the new
getsockopt_iter callback with sockopt_t.

Key changes:
- Replace (char __user *optval, int __user *optlen) with sockopt_t *opt
- Use opt->optlen for buffer length (input) and returned size (output)
- Use copy_to_iter() instead of copy_to_user()
- For CAN_RAW_FILTER and CAN_RAW_XL_VCID_OPTS: on -ERANGE, set
  opt->optlen to the required buffer size. The wrapper writes this
  back to userspace even on error, preserving the existing API that
  lets userspace discover the needed allocation size.

Output the complete corrected function(s).

```c
static int raw_getsockopt(struct socket *sock, int level, int optname,
		  char __user *optval, int __user *optlen)
{
struct sock *sk = sock->sk;
struct raw_sock *ro = raw_sk(sk);
int flag;
int len;
void *val;

if (level != SOL_CAN_RAW)
	return -EINVAL;
if (get_user(len, optlen))
	return -EFAULT;
if (len < 0)
	return -EINVAL;

switch (optname) {
case CAN_RAW_FILTER: {
	int err = 0;

	lock_sock(sk);
	if (ro->count > 0) {
		int fsize = ro->count * sizeof(struct can_filter);

		/* user space buffer to small for filter list? */
		if (len < fsize) {
			/* return -ERANGE and needed space in optlen */
			err = -ERANGE;
			if (put_user(fsize, optlen))
				err = -EFAULT;
		} else {
			if (len > fsize)
				len = fsize;
			if (copy_to_user(optval, ro->filter, len))
				err = -EFAULT;
		}
	} else {
		len = 0;
	}
	release_sock(sk);

	if (!err)
		err = put_user(len, optlen);
	return err;
}
case CAN_RAW_ERR_FILTER:
	if (len > sizeof(can_err_mask_t))
		len = sizeof(can_err_mask_t);
	val = &ro->err_mask;
	break;

case CAN_RAW_LOOPBACK:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->loopback;
	val = &flag;
	break;

case CAN_RAW_RECV_OWN_MSGS:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->recv_own_msgs;
	val = &flag;
	break;

case CAN_RAW_FD_FRAMES:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->fd_frames;
	val = &flag;
	break;

case CAN_RAW_XL_FRAMES:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->xl_frames;
	val = &flag;
	break;

case CAN_RAW_XL_VCID_OPTS: {
	int err = 0;

	/* user space buffer to small for VCID opts? */
	if (len < sizeof(ro->raw_vcid_opts)) {
		/* return -ERANGE and needed space in optlen */
		err = -ERANGE;
		if (put_user(sizeof(ro->raw_vcid_opts), optlen))
			err = -EFAULT;
	} else {
		if (len > sizeof(ro->raw_vcid_opts))
			len = sizeof(ro->raw_vcid_opts);
		if (copy_to_user(optval, &ro->raw_vcid_opts, len))
			err = -EFAULT;
	}
	if (!err)
		err = put_user(len, optlen);
	return err;
}
case CAN_RAW_JOIN_FILTERS:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->join_filters;
	val = &flag;
	break;

default:
	return -ENOPROTOOPT;
}

if (put_user(len, optlen))
	return -EFAULT;
if (copy_to_user(optval, val, len))
	return -EFAULT;
return 0;
}
