		  sockopt_t *opt)
{
struct sock *sk = sock->sk;
struct raw_sock *ro = raw_sk(sk);
int flag;
int len;
void *val;

if (level != SOL_CAN_RAW)
	return -EINVAL;
len = opt->optlen;
if (len < 0)
	return -EINVAL;

switch (optname) {
case CAN_RAW_FILTER: {
	int err = 0;

	lock_sock(sk);
	if (ro->count > 0) {
		int fsize = ro->count * sizeof(struct can_filter);

		/* user space buffer to small for filter list? */
		if (len < fsize) {
