				len = fsize;
			if (copy_to_iter(ro->filter, len,
					 &opt->iter_out) != len)
				err = -EFAULT;
		}
	} else {
		len = 0;
	}
	release_sock(sk);

	if (!err)
		opt->optlen = len;
	return err;
}
case CAN_RAW_ERR_FILTER:
	if (len > sizeof(can_err_mask_t))
		len = sizeof(can_err_mask_t);
	val = &ro->err_mask;
	break;

case CAN_RAW_LOOPBACK:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->loopback;
	val = &flag;
	break;

case CAN_RAW_RECV_OWN_MSGS:
	if (len > sizeof(int))
		len = sizeof(int);
	flag = ro->recv_own_msgs;
	val = &flag;
	break;

case CAN_RAW_FD_FRAMES:
	if (len > sizeof(int))
		len = sizeof(int);
