Implement the following feature in the code below: btrfs: free cached state outside critical section in wait_extent_bit().

Feature description:
There's no need to free the cached extent state record while holding the
io tree's spinlock, it's just making the critical section longer than it
needs to be. So just do it after unlocking the io tree.

Output the complete corrected function(s).

```c
/* File: fs/btrfs/extent-io-tree.c */
/*
* Wait for one or more bits to clear on a range in the state tree.
* The range [start, end] is inclusive.
* The tree lock is taken by this function
*/
static void wait_extent_bit(struct extent_io_tree *tree, u64 start, u64 end,
			   u32 bits, struct extent_state **cached_state)
{
       struct extent_state *state;

       btrfs_debug_check_extent_io_range(tree, start, end);

       spin_lock(&tree->lock);
again:
       /*
	* Maintain cached_state, as we may not remove it from the tree if there
	* are more bits than the bits we're waiting on set on this state.
	*/
       if (cached_state && *cached_state) {
	       state = *cached_state;
	       if (extent_state_in_tree(state) &&
		   state->start <= start && start < state->end)
		       goto process_node;
       }
       while (1) {
	       /*
		* This search will find all the extents that end after our
		* range starts.
		*/
	       state = tree_search(tree, start);
process_node:
	       if (!state)
		       break;
	       if (state->start > end)
		       goto out;

	       if (state->state & bits) {
		       DEFINE_WAIT(wait);

		       start = state->start;
		       refcount_inc(&state->refs);
		       prepare_to_wait(&state->wq, &wait, TASK_UNINTERRUPTIBLE);
		       spin_unlock(&tree->lock);
		       schedule();
		       spin_lock(&tree->lock);
		       finish_wait(&state->wq, &wait);
		       btrfs_free_extent_state(state);
		       goto again;
	       }
	       start = state->end + 1;

	       if (start > end)
		       break;

	       if (!cond_resched_lock(&tree->lock)) {
		       state = next_state(state);
		       goto process_node;
	       }
       }
out:
       /* This state is no longer useful, clear it and free it up. */
       if (cached_state && *cached_state) {
	       state = *cached_state;
	       *cached_state = NULL;
	       btrfs_free_extent_state(state);
       }
       spin_unlock(&tree->lock);
}
