Refactor the following code: ntfs: delete dead code.

Refactoring description:
We know "ret2" is zero so there is no need to check.  Delete the
if statement.

Output the complete corrected function(s).

```c
static ssize_t ntfs_dio_write_iter(struct kiocb *iocb, struct iov_iter *from)
{
ssize_t ret;

ret = iomap_dio_rw(iocb, from, &ntfs_dio_iomap_ops,
		&ntfs_write_dio_ops, 0, NULL, 0);
if (ret == -ENOTBLK)
	ret = 0;
else if (ret < 0)
	goto out;

if (iov_iter_count(from)) {
	loff_t offset, end;
	ssize_t written;
	int ret2;

	offset = iocb->ki_pos;
	iocb->ki_flags &= ~IOCB_DIRECT;
	written = iomap_file_buffered_write(iocb, from,
			&ntfs_write_iomap_ops, &ntfs_iomap_folio_ops,
			NULL);
	if (written < 0) {
		ret = written;
		goto out;
	}

	ret += written;
	end = iocb->ki_pos + written - 1;
	ret2 = filemap_write_and_wait_range(iocb->ki_filp->f_mapping,
			offset, end);
	if (ret2) {
		ret = -EIO;
		goto out;
	}
	if (!ret2)
		invalidate_mapping_pages(iocb->ki_filp->f_mapping,
					 offset >> PAGE_SHIFT,
					 end >> PAGE_SHIFT);
}

out:
return ret;
}
