Fix the following bug in the code below: xsk: validate MTU against usable frame size on bind.

Problem description:
AF_XDP bind currently accepts zero-copy pool configurations without
verifying that the device MTU fits into the usable frame space provided
by the UMEM chunk.

This becomes a problem since we started to respect tailroom which is
subtracted from chunk_size (among with headroom). 2k chunk size might
not provide enough space for standard 1500 MTU, so let us catch such
settings at bind time. Furthermore, validate whether underlying HW will
be able to satisfy configured MTU wrt XSK's frame size multiplied by
supported Rx buffer chain length (that is exposed via
net_device::xdp_zc_max_segs).

Output the complete corrected function(s).

```c
int xp_assign_dev(struct xsk_buff_pool *pool,
	  struct net_device *netdev, u16 queue_id, u16 flags)
{
bool force_zc, force_copy;
struct netdev_bpf bpf;
int err = 0;

ASSERT_RTNL();

force_zc = flags & XDP_ZEROCOPY;
force_copy = flags & XDP_COPY;

if (force_zc && force_copy)
	return -EINVAL;

if (xsk_get_pool_from_qid(netdev, queue_id))
	return -EBUSY;

pool->netdev = netdev;
pool->queue_id = queue_id;
err = xsk_reg_pool_at_qid(netdev, pool, queue_id);
if (err)
	return err;

if (flags & XDP_USE_SG)
	pool->umem->flags |= XDP_UMEM_SG_FLAG;

if (flags & XDP_USE_NEED_WAKEUP)
	pool->uses_need_wakeup = true;
/* Tx needs to be explicitly woken up the first time.  Also
 * for supporting drivers that do not implement this
 * feature. They will always have to call sendto() or poll().
 */
pool->cached_need_wakeup = XDP_WAKEUP_TX;

dev_hold(netdev);

if (force_copy)
	/* For copy-mode, we are done. */
	return 0;

if ((netdev->xdp_features & NETDEV_XDP_ACT_XSK) != NETDEV_XDP_ACT_XSK) {
	err = -EOPNOTSUPP;
	goto err_unreg_pool;
}

if (netdev->xdp_zc_max_segs == 1 && (flags & XDP_USE_SG)) {
	err = -EOPNOTSUPP;
	goto err_unreg_pool;
}

if (dev_get_min_mp_channel_count(netdev)) {
	err = -EBUSY;
	goto err_unreg_pool;
}

bpf.command = XDP_SETUP_XSK_POOL;
bpf.xsk.pool = pool;
bpf.xsk.queue_id = queue_id;

netdev_ops_assert_locked(netdev);
err = netdev->netdev_ops->ndo_bpf(netdev, &bpf);
if (err)
	goto err_unreg_pool;

if (!pool->dma_pages) {
	WARN(1, "Driver did not DMA map zero-copy buffers");
	err = -EINVAL;
	goto err_unreg_xsk;
}
pool->umem->zc = true;
pool->xdp_zc_max_segs = netdev->xdp_zc_max_segs;
return 0;

err_unreg_xsk:
xp_disable_drv_zc(pool);
err_unreg_pool:
if (!force_zc)
	err = 0; /* fallback to copy mode */
if (err) {
	xsk_clear_pool_at_qid(netdev, queue_id);
	dev_put(netdev);
}
return err;
}
```

```c
int xp_assign_dev(struct xsk_buff_pool *pool,
	  struct net_device *netdev, u16 queue_id, u16 flags)
{
u32 needed = netdev->mtu + ETH_PAD_LEN;
u32 segs = netdev->xdp_zc_max_segs;
bool mbuf = flags & XDP_USE_SG;
bool force_zc, force_copy;
struct netdev_bpf bpf;
u32 frame_size;
int err = 0;

ASSERT_RTNL();

force_zc = flags & XDP_ZEROCOPY;
force_copy = flags & XDP_COPY;

if (force_zc && force_copy)
	return -EINVAL;

if (xsk_get_pool_from_qid(netdev, queue_id))
	return -EBUSY;

pool->netdev = netdev;
pool->queue_id = queue_id;
err = xsk_reg_pool_at_qid(netdev, pool, queue_id);
if (err)
	return err;

if (mbuf)
	pool->umem->flags |= XDP_UMEM_SG_FLAG;

if (flags & XDP_USE_NEED_WAKEUP)
	pool->uses_need_wakeup = true;
/* Tx needs to be explicitly woken up the first time.  Also
 * for supporting drivers that do not implement this
 * feature. They will always have to call sendto() or poll().
 */
pool->cached_need_wakeup = XDP_WAKEUP_TX;

dev_hold(netdev);

if (force_copy)
	/* For copy-mode, we are done. */
	return 0;

if ((netdev->xdp_features & NETDEV_XDP_ACT_XSK) != NETDEV_XDP_ACT_XSK) {
	err = -EOPNOTSUPP;
	goto err_unreg_pool;
}

if (mbuf) {
	if (segs == 1) {
		err = -EOPNOTSUPP;
		goto err_unreg_pool;
	}
} else {
	segs = 1;
}

/* open-code xsk_pool_get_rx_frame_size() as pool->dev is not
 * set yet at this point; we are before getting down to driver
 */
frame_size = __xsk_pool_get_rx_frame_size(pool) -
	     xsk_pool_get_tailroom(mbuf);
frame_size = ALIGN_DOWN(frame_size, 128);

if (needed > frame_size * segs) {
	err = -EINVAL;
	goto err_unreg_pool;
}

if (dev_get_min_mp_channel_count(netdev)) {
	err = -EBUSY;
	goto err_unreg_pool;
}

bpf.command = XDP_SETUP_XSK_POOL;
bpf.xsk.pool = pool;
bpf.xsk.queue_id = queue_id;

netdev_ops_assert_locked(netdev);
err = netdev->netdev_ops->ndo_bpf(netdev, &bpf);
if (err)
	goto err_unreg_pool;

if (!pool->dma_pages) {
	WARN(1, "Driver did not DMA map zero-copy buffers");
	err = -EINVAL;
	goto err_unreg_xsk;
}
pool->umem->zc = true;
pool->xdp_zc_max_segs = netdev->xdp_zc_max_segs;
return 0;

err_unreg_xsk:
xp_disable_drv_zc(pool);
err_unreg_pool:
if (!force_zc)
	err = 0; /* fallback to copy mode */
if (err) {
	xsk_clear_pool_at_qid(netdev, queue_id);
	dev_put(netdev);
}
return err;
}
