Fix the following bug in the code below: netfilter: nfnetlink_osf: fix out-of-bounds read on option matching.

Problem description:
In nf_osf_match(), the nf_osf_hdr_ctx structure is initialized once
and passed by reference to nf_osf_match_one() for each fingerprint
checked. During TCP option parsing, nf_osf_match_one() advances the
shared ctx->optp pointer.

If a fingerprint perfectly matches, the function returns early without
restoring ctx->optp to its initial state. If the user has configured
NF_OSF_LOGLEVEL_ALL, the loop continues to the next fingerprint.
However, because ctx->optp was not restored, the next call to
nf_osf_match_one() starts parsing from the end of the options buffer.
This causes subsequent matches to read garbage data and fail
immediately, making it impossible to log more than one match or logging
incorrect matches.

Instead of using a shared ctx->optp pointer, pass the context as a
constant pointer and use a local pointer (optp) for TCP option
traversal. This makes nf_osf_match_one() strictly stateless from the
caller's perspective, ensuring every fingerprint check starts at the
correct option offset.

Output the complete corrected function(s).

```c
static bool nf_osf_match_one(const struct sk_buff *skb,
		     const struct nf_osf_user_finger *f,
		     int ttl_check,
		     struct nf_osf_hdr_ctx *ctx)
{
const __u8 *optpinit = ctx->optp;
unsigned int check_WSS = 0;
int fmatch = FMATCH_WRONG;
int foptsize, optnum;
u16 mss = 0;

if (ctx->totlen != f->ss || !nf_osf_ttl(skb, ttl_check, f->ttl))
	return false;

/*
 * Should not happen if userspace parser was written correctly.
 */
if (f->wss.wc >= OSF_WSS_MAX)
	return false;

/* Check options */

foptsize = 0;
for (optnum = 0; optnum < f->opt_num; ++optnum)
	foptsize += f->opt[optnum].length;

if (foptsize > MAX_IPOPTLEN ||
    ctx->optsize > MAX_IPOPTLEN ||
    ctx->optsize != foptsize)
	return false;

check_WSS = f->wss.wc;

for (optnum = 0; optnum < f->opt_num; ++optnum) {
	if (f->opt[optnum].kind == *ctx->optp) {
		__u32 len = f->opt[optnum].length;
		const __u8 *optend = ctx->optp + len;

		fmatch = FMATCH_OK;

		switch (*ctx->optp) {
		case OSFOPT_MSS:
			mss = ctx->optp[3];
			mss <<= 8;
			mss |= ctx->optp[2];

			mss = ntohs((__force __be16)mss);
			break;
		case OSFOPT_TS:
			break;
		}

		ctx->optp = optend;
	} else
		fmatch = FMATCH_OPT_WRONG;

	if (fmatch != FMATCH_OK)
		break;
}

if (fmatch != FMATCH_OPT_WRONG) {
	fmatch = FMATCH_WRONG;

	switch (check_WSS) {
	case OSF_WSS_PLAIN:
		if (f->wss.val == 0 || ctx->window == f->wss.val)
			fmatch = FMATCH_OK;
		break;
	case OSF_WSS_MSS:
		/*
		 * Some smart modems decrease mangle MSS to
		 * SMART_MSS_2, so we check standard, decreased
		 * and the one provided in the fingerprint MSS
		 * values.
		 */
#define SMART_MSS_1	1460
#define SMART_MSS_2	1448
		if (ctx->window == f->wss.val * mss ||
		    ctx->window == f->wss.val * SMART_MSS_1 ||
		    ctx->window == f->wss.val * SMART_MSS_2)
			fmatch = FMATCH_OK;
		break;
	case OSF_WSS_MTU:
		if (ctx->window == f->wss.val * (mss + 40) ||
		    ctx->window == f->wss.val * (SMART_MSS_1 + 40) ||
		    ctx->window == f->wss.val * (SMART_MSS_2 + 40))
			fmatch = FMATCH_OK;
		break;
	case OSF_WSS_MODULO:
		if ((ctx->window % f->wss.val) == 0)
			fmatch = FMATCH_OK;
		break;
	}
}

if (fmatch != FMATCH_OK)
	ctx->optp = optpinit;

return fmatch == FMATCH_OK;
}
