	const struct v4l2_pix_format *fmt = &node->fmt.fmt.pix;
	const struct unicam_format_info *fmtinfo;

	fmtinfo = unicam_find_format_by_code(format->code,
					     UNICAM_SD_PAD_SOURCE_IMAGE);
	if (WARN_ON(!fmtinfo)) {
		ret = -EPIPE;
		goto out;
