Fix the following bug in the code below: hwmon: (tps53679) Fix device ID comparison and printing in tps53676_identify().

Problem description:
tps53676_identify() uses strncmp() to compare the device ID buffer
against a byte sequence containing embedded non-printable bytes
(\x53\x67\x60). strncmp() is semantically wrong for binary data
comparison; use memcmp() instead.

Additionally, the buffer from i2c_smbus_read_block_data() is not
NUL-terminated, so printing it with "%s" in the error path is
undefined behavior and may read past the buffer. Use "%*ph" to
hex-dump the actual bytes returned.

Per the datasheet, the expected device ID is the 6-byte sequence
54 49 53 67 60 00 ("TI\x53\x67\x60\x00"), so compare all 6 bytes
including the trailing NUL.

Output the complete corrected function(s).

```c
static int tps53676_identify(struct i2c_client *client,
		     struct pmbus_driver_info *info)
{
u8 buf[I2C_SMBUS_BLOCK_MAX];
int phases_a = 0, phases_b = 0;
int i, ret;

ret = i2c_smbus_read_block_data(client, PMBUS_IC_DEVICE_ID, buf);
if (ret < 0)
	return ret;
if (strncmp("TI\x53\x67\x60", buf, 5)) {
	dev_err(&client->dev, "Unexpected device ID: %s\n", buf);
	return -ENODEV;
}

ret = i2c_smbus_read_block_data(client, TPS53676_USER_DATA_03, buf);
if (ret < 0)
	return ret;
if (ret != 24)
	return -EIO;
for (i = 0; i < 2 * TPS53676_MAX_PHASES; i += 2) {
	if (buf[i + 1] & 0x80) {
		if (buf[i] & 0x08)
			phases_b++;
		else
			phases_a++;
	}
}

info->format[PSC_VOLTAGE_OUT] = linear;
info->pages = 1;
info->phases[0] = phases_a;
if (phases_b > 0) {
	info->pages = 2;
	info->phases[1] = phases_b;
}
return 0;
}
```

```c
static int tps53676_identify(struct i2c_client *client,
		     struct pmbus_driver_info *info)
{
u8 buf[I2C_SMBUS_BLOCK_MAX];
int phases_a = 0, phases_b = 0;
int i, ret;

ret = i2c_smbus_read_block_data(client, PMBUS_IC_DEVICE_ID, buf);
if (ret < 0)
	return ret;
if (ret != 6 || memcmp(buf, "TI\x53\x67\x60\x00", 6)) {
	dev_err(&client->dev, "Unexpected device ID: %*ph\n", ret, buf);
	return -ENODEV;
}

ret = i2c_smbus_read_block_data(client, TPS53676_USER_DATA_03, buf);
if (ret < 0)
	return ret;
if (ret != 24)
	return -EIO;
for (i = 0; i < 2 * TPS53676_MAX_PHASES; i += 2) {
	if (buf[i + 1] & 0x80) {
		if (buf[i] & 0x08)
			phases_b++;
		else
			phases_a++;
	}
}

info->format[PSC_VOLTAGE_OUT] = linear;
info->pages = 1;
info->phases[0] = phases_a;
if (phases_b > 0) {
	info->pages = 2;
	info->phases[1] = phases_b;
}
return 0;
}
