Implement the following feature in the code below: usb: typec: cros_ec_ucsi: Load driver from OF and ACPI definitions.

Feature description:
Add support for cros_ec_ucsi to load based on "google,cros-ec-ucsi"
compatible devices and "GOOG0021" ACPI nodes.

Output the complete corrected function(s).

```c
static int cros_ucsi_probe(struct platform_device *pdev)
{
struct device *dev = &pdev->dev;
struct cros_ec_dev *ec_data = dev_get_drvdata(dev->parent);
struct cros_ucsi_data *udata;
int ret;

udata = devm_kzalloc(dev, sizeof(*udata), GFP_KERNEL);
if (!udata)
	return -ENOMEM;

udata->dev = dev;

udata->ec = ec_data->ec_dev;
if (!udata->ec)
	return dev_err_probe(dev, -ENODEV, "couldn't find parent EC device\n");

platform_set_drvdata(pdev, udata);

INIT_WORK(&udata->work, cros_ucsi_work);
INIT_DELAYED_WORK(&udata->write_tmo, cros_ucsi_write_timeout);
init_completion(&udata->complete);

udata->ucsi = ucsi_create(dev, &cros_ucsi_ops);
if (IS_ERR(udata->ucsi))
	return dev_err_probe(dev, PTR_ERR(udata->ucsi), "failed to allocate UCSI instance\n");

ucsi_set_drvdata(udata->ucsi, udata);

udata->nb.notifier_call = cros_ucsi_event;
ret = cros_usbpd_register_notify(&udata->nb);
if (ret) {
	dev_err_probe(dev, ret, "failed to register notifier\n");
	ucsi_destroy(udata->ucsi);
	return ret;
}

ret = ucsi_register(udata->ucsi);
if (ret) {
	dev_err_probe(dev, ret, "failed to register UCSI\n");
	cros_ucsi_destroy(udata);
	return ret;
}

return 0;
}
