	sc->status = SMBDIRECT_SOCKET_DISCONNECTED;
	smb_direct_disconnect_rdma_work(&sc->disconnect_work);
	break;
}
default:
	pr_err("Unexpected RDMA CM event. cm_id=%p, event=%s (%d)\n",
	       cm_id, rdma_event_msg(event->event),
	       event->event);
	break;
}
return 0;
