Implement the following feature in the code below: macvlan: avoid spinlock contention in macvlan_broadcast_enqueue().

Feature description:
Under high stress, we spend a lot of time cloning skbs,
then acquiring a spinlock, then freeing the clone because
the queue is full.

Add a shortcut to avoid these costs under pressure.

Output the complete corrected function(s).

```c
/* File: drivers/net/macvlan.c */
static void macvlan_broadcast_enqueue(struct macvlan_port *port,
			      const struct macvlan_dev *src,
			      struct sk_buff *skb)
{
u32 bc_queue_len_used = READ_ONCE(port->bc_queue_len_used);
struct sk_buff *nskb;
int err = -ENOMEM;

nskb = skb_clone(skb, GFP_ATOMIC);
if (!nskb)
	goto err;

MACVLAN_SKB_CB(nskb)->src = src;

spin_lock(&port->bc_queue.lock);
if (skb_queue_len(&port->bc_queue) < bc_queue_len_used) {
	if (src)
		dev_hold(src->dev);
	__skb_queue_tail(&port->bc_queue, nskb);
	err = 0;
}
spin_unlock(&port->bc_queue.lock);

queue_work(system_dfl_wq, &port->bc_work);

if (err)
	goto free_nskb;

return;

free_nskb:
kfree_skb(nskb);
err:
dev_core_stats_rx_dropped_inc(skb->dev);
}
```

