Refactor the following code: hwmon: (asus_atk0110) Check ACPI_COMPANION() against NULL.

Refactor strategy: add error return

Refactoring description:
Every platform driver can be forced to match a device that doesn't match
its list of device IDs because of device_match_driver_override(), so
platform drivers that rely on the existence of a device's ACPI companion
object need to verify its presence.

Accordingly, add a requisite ACPI_HANDLE() check against NULL to the
asus_atk0110 hwmon driver.

Output the complete corrected function(s).

```c
static int atk_probe(struct platform_device *pdev)
{
acpi_status ret;
int err;
struct acpi_buffer buf;
union acpi_object *obj;
struct atk_data *data;

dev_dbg(&pdev->dev, "adding...\n");

data = devm_kzalloc(&pdev->dev, sizeof(*data), GFP_KERNEL);
if (!data)
	return -ENOMEM;

data->dev = &pdev->dev;
data->atk_handle = ACPI_HANDLE(&pdev->dev);
INIT_LIST_HEAD(&data->sensor_list);
data->disable_ec = false;

buf.length = ACPI_ALLOCATE_BUFFER;
ret = acpi_evaluate_object_typed(data->atk_handle, BOARD_ID, NULL,
		&buf, ACPI_TYPE_PACKAGE);
if (ret != AE_OK) {
	dev_dbg(&pdev->dev, "atk: method MBIF not found\n");
} else {
	obj = buf.pointer;
	if (obj->package.count >= 2) {
		union acpi_object *id = &obj->package.elements[1];
		if (id->type == ACPI_TYPE_STRING)
			dev_dbg(&pdev->dev, "board ID = %s\n",
				id->string.pointer);
	}
	ACPI_FREE(buf.pointer);
}

err = atk_probe_if(data);
if (err) {
	dev_err(&pdev->dev, "No usable hwmon interface detected\n");
	goto out;
}

if (data->old_interface) {
	dev_dbg(&pdev->dev, "Using old hwmon interface\n");
	err = atk_enumerate_old_hwmon(data);
} else {
	dev_dbg(&pdev->dev, "Using new hwmon interface\n");
	err = atk_enumerate_new_hwmon(data);
}
if (err < 0)
	goto out;
if (err == 0) {
	dev_info(&pdev->dev,
		 "No usable sensor detected, bailing out\n");
	err = -ENODEV;
	goto out;
}

err = atk_init_attribute_groups(data);
if (err)
	goto out;
err = atk_register_hwmon(data);
if (err)
	goto out;

atk_debugfs_init(data);

platform_set_drvdata(pdev, data);

return 0;
out:
if (data->disable_ec)
	atk_ec_ctl(data, 0);
return err;
}
