Implement the following feature in the code below: hfsplus: fix logic of alloc/free b-tree node.

Feature description:
The hfs_bmap_alloc() and hfs_bmap_free() modify
the b-tree's counters and nodes' bitmap of b-tree.
However, hfs_btree_write() synchronizes the state of
in-core b-tree's counters and node's bitmap with
b-tree's descriptor in header node. Postponing this
synchronization could result in inconsistent state of
file system volume. This patch adds calling of
hfs_btree_write() in hfs_bmap_alloc() and hfs_bmap_free()
methods.

Output the complete corrected function(s).

```c
struct hfs_bnode *hfs_bmap_alloc(struct hfs_btree *tree)
{
struct hfs_bnode *node, *next_node;
struct hfs_bmap_ctx ctx;
struct page *page;
u32 nidx, idx;
u8 *data, byte, m;
int i, res;

lockdep_assert_held(&tree->tree_lock);

res = hfs_bmap_reserve(tree, 1);
if (res)
	return ERR_PTR(res);

nidx = 0;
node = hfs_bnode_find(tree, nidx);
if (IS_ERR(node))
	return node;

page = hfs_bmap_get_map_page(node, &ctx, 0);
if (IS_ERR(page)) {
	res = PTR_ERR(page);
	hfs_bnode_put(node);
	return ERR_PTR(res);
}

data = kmap_local_page(page);
idx = 0;

for (;;) {
	while (ctx.len) {
		byte = data[ctx.off];
		if (byte != 0xff) {
			for (m = 0x80, i = 0; i < 8; m >>= 1, i++) {
				if (!(byte & m)) {
					idx += i;
					data[ctx.off] |= m;
					set_page_dirty(page);
					kunmap_local(data);
					tree->free_nodes--;
					mark_inode_dirty(tree->inode);
					hfs_bnode_put(node);
					return hfs_bnode_create(tree,
						idx);
				}
			}
		}
		if (++ctx.off >= PAGE_SIZE) {
			kunmap_local(data);
			page = node->page[++ctx.page_idx];
			data = kmap_local_page(page);
			ctx.off = 0;
		}
		idx += 8;
		ctx.len--;
	}
	kunmap_local(data);
	nidx = node->next;
	if (!nidx) {
		hfs_dbg("create new bmap node\n");
		next_node = hfs_bmap_new_bmap(node, idx);
	} else
		next_node = hfs_bnode_find(tree, nidx);
	hfs_bnode_put(node);
	if (IS_ERR(next_node))
		return next_node;
	node = next_node;

	page = hfs_bmap_get_map_page(node, &ctx, 0);
	if (IS_ERR(page)) {
		res = PTR_ERR(page);
		hfs_bnode_put(node);
		return ERR_PTR(res);
	}
	data = kmap_local_page(page);
}
}
```

