Implement the following feature in the code below: bpf: Add helper to detect indirect jump targets.

Feature description:
Introduce helper bpf_insn_is_indirect_target to check whether a BPF
instruction is an indirect jump target.

Since the verifier knows which instructions are indirect jump targets,
add a new flag indirect_target to struct bpf_insn_aux_data to mark
them. The verifier sets this flag when verifying an indirect jump target
instruction, and the helper checks the flag to determine whether an
instruction is an indirect jump target.

Output the complete corrected function(s).

```c
/* gotox *dst_reg */
static int check_indirect_jump(struct bpf_verifier_env *env, struct bpf_insn *insn)
{
struct bpf_verifier_state *other_branch;
struct bpf_reg_state *dst_reg;
struct bpf_map *map;
u32 min_index, max_index;
int err = 0;
int n;
int i;

dst_reg = reg_state(env, insn->dst_reg);
if (dst_reg->type != PTR_TO_INSN) {
	verbose(env, "R%d has type %s, expected PTR_TO_INSN\n",
		     insn->dst_reg, reg_type_str(env, dst_reg->type));
	return -EINVAL;
}

map = dst_reg->map_ptr;
if (verifier_bug_if(!map, env, "R%d has an empty map pointer", insn->dst_reg))
	return -EFAULT;

if (verifier_bug_if(map->map_type != BPF_MAP_TYPE_INSN_ARRAY, env,
		    "R%d has incorrect map type %d", insn->dst_reg, map->map_type))
	return -EFAULT;

err = indirect_jump_min_max_index(env, insn->dst_reg, map, &min_index, &max_index);
if (err)
	return err;

/* Ensure that the buffer is large enough */
if (!env->gotox_tmp_buf || env->gotox_tmp_buf->cnt < max_index - min_index + 1) {
	env->gotox_tmp_buf = bpf_iarray_realloc(env->gotox_tmp_buf,
						max_index - min_index + 1);
	if (!env->gotox_tmp_buf)
		return -ENOMEM;
}

n = bpf_copy_insn_array_uniq(map, min_index, max_index, env->gotox_tmp_buf->items);
if (n < 0)
	return n;
if (n == 0) {
	verbose(env, "register R%d doesn't point to any offset in map id=%d\n",
		     insn->dst_reg, map->id);
	return -EINVAL;
}

for (i = 0; i < n - 1; i++) {
	other_branch = push_stack(env, env->gotox_tmp_buf->items[i],
				  env->insn_idx, env->cur_state->speculative);
	if (IS_ERR(other_branch))
		return PTR_ERR(other_branch);
}
env->insn_idx = env->gotox_tmp_buf->items[n-1];
return INSN_IDX_UPDATED;
}
```

