	mark_indirect_target(env, env->gotox_tmp_buf->items[i]);
	other_branch = push_stack(env, env->gotox_tmp_buf->items[i],
				  env->insn_idx, env->cur_state->speculative);
	if (IS_ERR(other_branch))
