Implement the following feature in the code below: mm/memory: inline unmap_mapping_range_vma() into unmap_mapping_range_tree().

Feature description:
Let's remove the number of unmap-related functions that cause confusion by
inlining unmap_mapping_range_vma() into its single caller.  The end result
looks pretty readable.

Output the complete corrected function(s).

```c
/* File: mm/memory.c */
static inline void unmap_mapping_range_tree(struct rb_root_cached *root,
				    pgoff_t first_index,
				    pgoff_t last_index,
				    struct zap_details *details)
{
struct vm_area_struct *vma;
pgoff_t vba, vea, zba, zea;

vma_interval_tree_foreach(vma, root, first_index, last_index) {
	vba = vma->vm_pgoff;
	vea = vba + vma_pages(vma) - 1;
	zba = max(first_index, vba);
	zea = min(last_index, vea);

	unmap_mapping_range_vma(vma,
		((zba - vba) << PAGE_SHIFT) + vma->vm_start,
		((zea - vba + 1) << PAGE_SHIFT) + vma->vm_start,
			details);
}
}
```

```c
/* File: mm/memory.c */
static inline void unmap_mapping_range_tree(struct rb_root_cached *root,
				    pgoff_t first_index,
				    pgoff_t last_index,
				    struct zap_details *details)
{
struct vm_area_struct *vma;
pgoff_t vba, vea, zba, zea;
unsigned long start, size;
struct mmu_gather tlb;

vma_interval_tree_foreach(vma, root, first_index, last_index) {
	vba = vma->vm_pgoff;
	vea = vba + vma_pages(vma) - 1;
	zba = max(first_index, vba);
	zea = min(last_index, vea);
	start = ((zba - vba) << PAGE_SHIFT) + vma->vm_start;
	size = (zea - zba + 1) << PAGE_SHIFT;

	tlb_gather_mmu(&tlb, vma->vm_mm);
	zap_page_range_single_batched(&tlb, vma, start, size, details);
	tlb_finish_mmu(&tlb);
}
}
