Fix the following bug in the code below: rxrpc: Fix key quota calculation for multitoken keys.

Problem description:
In the rxrpc key preparsing, every token extracted sets the proposed quota
value, but for multitoken keys, this will overwrite the previous proposed
quota, losing it.

Fix this by adding to the proposed quota instead.

Output the complete corrected function(s).

```c
/*
* Preparse an rxrpc defined key.
*
* Data should be of the form:
*	OFFSET	LEN	CONTENT
*	0	4	key interface version number
*	4	2	security index (type)
*	6	2	ticket length
*	8	4	key expiry time (time_t)
*	12	4	kvno
*	16	8	session key
*	24	[len]	ticket
*
* if no data is provided, then a no-security key is made
*/
static int rxrpc_preparse(struct key_preparsed_payload *prep)
{
       const struct rxrpc_key_data_v1 *v1;
       struct rxrpc_key_token *token, **pp;
       time64_t expiry;
       size_t plen;
       u32 kver;
       int ret;

       _enter("%zu", prep->datalen);

       /* handle a no-security key */
       if (!prep->data && prep->datalen == 0)
	       return 0;

       /* determine if the XDR payload format is being used */
       if (prep->datalen > 7 * 4) {
	       ret = rxrpc_preparse_xdr(prep);
	       if (ret != -EPROTO)
		       return ret;
       }

       /* get the key interface version number */
       ret = -EINVAL;
       if (prep->datalen <= 4 || !prep->data)
	       goto error;
       memcpy(&kver, prep->data, sizeof(kver));
       prep->data += sizeof(kver);
       prep->datalen -= sizeof(kver);

       _debug("KEY I/F VERSION: %u", kver);

       ret = -EKEYREJECTED;
       if (kver != 1)
	       goto error;

       /* deal with a version 1 key */
       ret = -EINVAL;
       if (prep->datalen < sizeof(*v1))
	       goto error;

       v1 = prep->data;
       if (prep->datalen != sizeof(*v1) + v1->ticket_length)
	       goto error;

       _debug("SCIX: %u", v1->security_index);
       _debug("TLEN: %u", v1->ticket_length);
       _debug("EXPY: %x", v1->expiry);
       _debug("KVNO: %u", v1->kvno);
       _debug("SKEY: %02x%02x%02x%02x%02x%02x%02x%02x",
	      v1->session_key[0], v1->session_key[1],
	      v1->session_key[2], v1->session_key[3],
	      v1->session_key[4], v1->session_key[5],
	      v1->session_key[6], v1->session_key[7]);
       if (v1->ticket_length >= 8)
	       _debug("TCKT: %02x%02x%02x%02x%02x%02x%02x%02x",
		      v1->ticket[0], v1->ticket[1],
		      v1->ticket[2], v1->ticket[3],
		      v1->ticket[4], v1->ticket[5],
		      v1->ticket[6], v1->ticket[7]);

       ret = -EPROTONOSUPPORT;
       if (v1->security_index != RXRPC_SECURITY_RXKAD)
	       goto error;

       plen = sizeof(*token->kad) + v1->ticket_length;
       prep->quotalen = plen + sizeof(*token);

       ret = -ENOMEM;
       token = kzalloc_obj(*token);
       if (!token)
	       goto error;
       token->kad = kzalloc(plen, GFP_KERNEL);
       if (!token->kad)
	       goto error_free;

       token->security_index		= RXRPC_SECURITY_RXKAD;
       token->kad->ticket_len		= v1->ticket_length;
       token->kad->expiry		= v1->expiry;
       token->kad->kvno		= v1->kvno;
       memcpy(&token->kad->session_key, &v1->session_key, 8);
       memcpy(&token->kad->ticket, v1->ticket, v1->ticket_length);

       /* count the number of tokens attached */
       prep->payload.data[1] = (void *)((unsigned long)prep->payload.data[1] + 1);


