Refactoring description:
With this the low level send functions are in common,
we'll have to do some more changes in generic smb code
in order to use smbdirect_connection_send_iter() instead
of looping around smbdirect_connection_send_single_iter().

David's cleanups will allow us to use
smbdirect_connection_send_iter().

Output the complete corrected function(s).

```c
/* File: fs/smb/client/smbdirect.c */
static int smbd_post_send_iter(struct smbdirect_socket *sc,
		       struct smbdirect_send_batch *batch,
		       struct iov_iter *iter,
		       u32 remaining_data_length)
{
struct smbdirect_socket_parameters *sp = &sc->parameters;
int rc;
int header_length;
int data_length;
struct smbdirect_send_io *request;
struct smbdirect_data_transfer *packet;
u16 new_credits = 0;
struct smbdirect_send_batch _batch;

if (iter) {
	header_length = sizeof(struct smbdirect_data_transfer);
	if (WARN_ON_ONCE(remaining_data_length == 0 ||
			 iov_iter_count(iter) > remaining_data_length))
		return -EINVAL;
} else {
	/* If this is a packet without payload, don't send padding */
	header_length = offsetof(struct smbdirect_data_transfer, padding);
	if (WARN_ON_ONCE(remaining_data_length))
		return -EINVAL;
}

if (!batch) {
	smbd_send_batch_init(&_batch, false, 0);
	batch = &_batch;
}

rc = wait_for_send_bcredit(sc, batch);
if (rc) {
	log_outgoing(ERR, "disconnected not sending on wait_bcredit\n");
	rc = -EAGAIN;
	goto err_wait_bcredit;
}

rc = wait_for_send_lcredit(sc, batch);
if (rc) {
	log_outgoing(ERR, "disconnected not sending on wait_lcredit\n");
	rc = -EAGAIN;
	goto err_wait_lcredit;
}

rc = wait_for_send_credits(sc, batch);
if (rc) {
	log_outgoing(ERR, "disconnected not sending on wait_credit\n");
	rc = -EAGAIN;
	goto err_wait_credit;
}

new_credits = smbdirect_connection_grant_recv_credits(sc);
if (new_credits == 0 &&
    atomic_read(&sc->send_io.credits.count) == 0 &&
    atomic_read(&sc->recv_io.credits.count) == 0) {
	queue_work(sc->workqueue, &sc->recv_io.posted.refill_work);
	rc = wait_event_interruptible(sc->send_io.credits.wait_queue,
				      atomic_read(&sc->send_io.credits.count) >= 1 ||
				      atomic_read(&sc->recv_io.credits.available) >= 1 ||
				      sc->status != SMBDIRECT_SOCKET_CONNECTED);
	if (sc->status != SMBDIRECT_SOCKET_CONNECTED)
		rc = -ENOTCONN;
	if (rc < 0) {
		log_outgoing(ERR, "disconnected not sending on last credit\n");
		rc = -EAGAIN;
		goto err_wait_credit;
	}

	new_credits = smbdirect_connection_grant_recv_credits(sc);
}

request = smbdirect_connection_alloc_send_io(sc);
if (IS_ERR(request)) {
	rc = PTR_ERR(request);
	goto err_alloc;
}

