				    vma, vma->vm_end - vma->vm_start,
				    virt_to_page(dma_obj->vaddr));
       } else {
	       ret = dma_mmap_wc(drm_dev_dma_dev(dma_obj->base.dev), vma,
				 dma_obj->vaddr, dma_obj->dma_addr,
				 vma->vm_end - vma->vm_start);
