Implement the following feature in the code below: zram: propagate read_from_bdev_async() errors.

Feature description:
When read_from_bdev_async() fails to chain bio, for instance fails to
allocate request or bio, we need to propagate the error condition so that
upper layer is aware of it.  zram already does that by setting
BLK_STS_IOERR ->bi_status, but only for sync reads.  Change async read
path to return its error status so that async errors are also handled.

Output the complete corrected function(s).

```c
/* File: drivers/block/zram/zram_drv.c */
static void read_from_bdev_async(struct zram *zram, struct page *page,
			 u32 index, unsigned long blk_idx,
			 struct bio *parent)
{
struct zram_rb_req *req;
struct bio *bio;

req = kmalloc_obj(*req, GFP_NOIO);
if (!req)
	return;

bio = bio_alloc(zram->bdev, 1, parent->bi_opf, GFP_NOIO);
if (!bio) {
	kfree(req);
	return;
}

req->zram = zram;
req->index = index;
req->blk_idx = blk_idx;
req->bio = bio;
req->parent = parent;

bio->bi_iter.bi_sector = blk_idx * (PAGE_SIZE >> 9);
bio->bi_private = req;
bio->bi_end_io = zram_async_read_endio;

__bio_add_page(bio, page, PAGE_SIZE, 0);
bio_inc_remaining(parent);
submit_bio(bio);
}

/* --- separate code section --- */

/* File: drivers/block/zram/zram_drv.c */
static int read_from_bdev(struct zram *zram, struct page *page, u32 index,
		  unsigned long blk_idx, struct bio *parent)
{
atomic64_inc(&zram->stats.bd_reads);
if (!parent) {
	if (WARN_ON_ONCE(!IS_ENABLED(ZRAM_PARTIAL_IO)))
		return -EIO;
	return read_from_bdev_sync(zram, page, index, blk_idx);
}
read_from_bdev_async(zram, page, index, blk_idx, parent);
return 0;
}
